import { GoogleGenAI, Chat } from "@google/genai";
import { Product } from "../types";

/**
 * Creates a new chat session using the Gemini 3 Pro model.
 */
export const startNETTOOLZChat = (): Chat => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  return ai.chats.create({
    model: 'gemini-3-pro-preview',
    config: {
      systemInstruction: `You are the NETTOOLZ Pro Assistant, a world-class expert in digital networking tools, security software, and digital assets.

      Your core knowledge base includes:
      - Private & Residential Proxies.
      - Premium VPNs.
      - RDP & VPS.
      - Traffic Logs & SEO Tools.

      Guidelines:
      1. Professional & Precise: Use technical terminology correctly.
      2. Aesthetic Focus: Our brand is Sky Blue and White. Mention this occasionally.
      3. Safety First: Strictly decline illegal hacking requests.`,
      temperature: 0.8,
      thinkingConfig: { thinkingBudget: 16384 },
    },
  });
};

/**
 * Generates a high-quality product image using the Gemini 2.5 Flash Image model.
 * Adheres to the sky-blue and white aesthetic.
 */
export const generateProductImage = async (product: Product): Promise<string | null> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = `A professional, ultra-high-definition 3D tech asset illustration for an e-commerce site named NETTOOLZ.
  Product: ${product.name}. 
  Description: ${product.description}. 
  Style: Modern minimalist 3D render, high-tech networking theme.
  Color Palette: Primary Sky Blue (#0ea5e9) and Crisp White. 
  Background: Pure clean white.
  Composition: Central 3D icon or server hardware representation, soft ambient occlusion shadows, professional studio lighting.
  Quality: 4k resolution, octane render style, clean vectors, sharp edges. No text.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: { parts: [{ text: prompt }] },
    });

    for (const part of response.candidates[0].content.parts) {
      if (part.inlineData) {
        return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
      }
    }
  } catch (error) {
    console.error("Gemini Image Generation Error:", error);
  }
  return null;
};

import React, { useState, useEffect, useCallback } from 'react';
import { Product, CartItem, ViewState, SiteSettings, AdminUser, User, UserOrder } from './types';
import { INITIAL_PRODUCTS, CATEGORIES } from './constants';
import { dbService } from './services/dbService';
import { generateProductImage } from './services/geminiService';
import Navbar from './components/Navbar';
import ProductCard from './components/ProductCard';
import GeminiAssistant from './components/GeminiAssistant';
import AdminLogin from './components/AdminLogin';
import AdminDashboard from './components/AdminDashboard';
import UserAuth from './components/UserAuth';
import UserProfile from './components/UserProfile';
import WalletFunding from './components/WalletFunding';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<ViewState>('home');
  const [selectedCategory, setSelectedCategory] = useState<string | null>(null);
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [isProcessingCheckout, setIsProcessingCheckout] = useState(false);
  const [isLoadingDB, setIsLoadingDB] = useState(true);
  const [isGeneratingImages, setIsGeneratingImages] = useState(false);

  const [products, setProducts] = useState<Product[]>([]);
  const [admins, setAdmins] = useState<AdminUser[]>([{ id: '1', username: 'Admin', role: 'super' }]);
  const [settings, setSettings] = useState<SiteSettings>({
    currency: 'NGN',
    currencySymbol: '₦',
    storeName: 'NETTOOLZ',
    usdtToNairaRate: 1650, 
    geminiApiKey: '',
    categories: CATEGORIES,
    paymentMethods: [
      { 
        id: 'bank1', 
        type: 'bank', 
        name: 'KoralPay (Automated Bank)', 
        details: 'Transfer to the virtual account generated at checkout.', 
        isActive: true,
        isAutomated: true,
        apiPublicKey: 'pk_live_nettoolz_7721',
        merchantId: 'MER-88122'
      },
      { 
        id: 'crypto1', 
        type: 'crypto', 
        name: 'Crypto (Instant Credit)', 
        details: 'Payment credits after 1 network confirmation.', 
        walletAddress: 'TYxxxxxxxxxxxxxxxxxxxxxx',
        network: 'TRC20',
        isActive: true,
        isAutomated: true,
        apiPublicKey: 'pk_live_crypto_9921',
        merchantId: 'MER-99123'
      }
    ]
  });
  const [isAdminLoggedIn, setIsAdminLoggedIn] = useState(false);
  const [users, setUsers] = useState<User[]>([]);
  const [currentUser, setCurrentUser] = useState<User | null>(null);

  // Auto-generate images for products using placeholders
  const autoGenerateMissingImages = useCallback(async (currentProducts: Product[]) => {
    const productsToUpdate = currentProducts.filter(p => p.image.includes('picsum.photos'));
    if (productsToUpdate.length === 0) return;

    setIsGeneratingImages(true);
    const updatedProducts = [...currentProducts];

    for (let i = 0; i < productsToUpdate.length; i++) {
      const p = productsToUpdate[i];
      const newImage = await generateProductImage(p);
      if (newImage) {
        const index = updatedProducts.findIndex(item => item.id === p.id);
        if (index !== -1) {
          updatedProducts[index] = { ...updatedProducts[index], image: newImage };
        }
      }
    }

    setProducts(updatedProducts);
    await dbService.saveProducts(updatedProducts);
    setIsGeneratingImages(false);
  }, []);

  useEffect(() => {
    const initApp = async () => {
      try {
        await dbService.init();

        const savedSettings = await dbService.getSettings();
        if (savedSettings) setSettings(savedSettings);
        else await dbService.saveSettings(settings);

        const savedProducts = await dbService.getAllProducts();
        let currentProductsList = [];
        if (savedProducts && savedProducts.length > 0) {
          currentProductsList = savedProducts;
        } else {
          await dbService.saveProducts(INITIAL_PRODUCTS);
          currentProductsList = INITIAL_PRODUCTS;
        }
        setProducts(currentProductsList);

        const savedAdmins = await dbService.getAllAdmins();
        if (savedAdmins && savedAdmins.length > 0) setAdmins(savedAdmins);
        else await dbService.saveAdmins(admins);

        const savedUsers = await dbService.getAllUsers();
        setUsers(savedUsers);

        const savedAdmin = localStorage.getItem('nettoolz_admin_logged');
        if (savedAdmin === 'true') setIsAdminLoggedIn(true);

        const loggedUserEmail = localStorage.getItem('nettoolz_logged_user_email');
        if (loggedUserEmail) {
          const found = savedUsers.find(u => u.email === loggedUserEmail);
          if (found) setCurrentUser(found);
        }

        // After initial load, if any product is using a placeholder, generate a pro image
        autoGenerateMissingImages(currentProductsList);

      } catch (err) {
        console.error("Database initialization failed:", err);
      } finally {
        setIsLoadingDB(false);
      }
    };

    initApp();
  }, [autoGenerateMissingImages]);

  const handleUpdateProducts = async (newProducts: Product[]) => {
    setProducts(newProducts);
    await dbService.saveProducts(newProducts);
  };

  const handleUpdateSettings = async (newSettings: SiteSettings) => {
    setSettings(newSettings);
    await dbService.saveSettings(newSettings);
  };

  const handleUpdateAdmins = async (newAdmins: AdminUser[]) => {
    setAdmins(newAdmins);
    await dbService.saveAdmins(newAdmins);
  };

  const handleAuth = async (user: User) => {
    const exists = users.find(u => u.email === user.email);
    const updatedUsers = exists 
      ? users.map(u => u.email === user.email ? user : u) 
      : [...users, user];

    setUsers(updatedUsers);
    setCurrentUser(user);
    await dbService.saveUser(user);
    localStorage.setItem('nettoolz_logged_user_email', user.email);
    setCurrentView('profile');
  };

  const handleFundSuccess = async (amount: number) => {
    if (!currentUser) return;
    const updatedUser = {
      ...currentUser,
      balance: currentUser.balance + amount
    };
    setUsers(prev => prev.map(u => u.email === updatedUser.email ? updatedUser : u));
    setCurrentUser(updatedUser);
    await dbService.saveUser(updatedUser);
  };

  const addToCart = (product: Product) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) return prev.map(item => item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item);
      return [...prev, { ...product, quantity: 1 }];
    });
    setIsCartOpen(true);
  };

  const handleCheckout = async () => {
    if (!currentUser) { setCurrentView('profile'); setIsCartOpen(false); return; }
    const total = cart.reduce((acc, item) => acc + (item.price * item.quantity), 0);
    if (currentUser.balance < total) { alert('Insufficient balance.'); setCurrentView('fund_wallet'); setIsCartOpen(false); return; }

    setIsProcessingCheckout(true);
    await new Promise(resolve => setTimeout(resolve, 1500));
    const newOrders: UserOrder[] = cart.map(item => ({ id: Date.now().toString() + Math.random(), productId: item.id, productName: item.name, content: item.secretContent || 'Processing...', price: item.price, timestamp: Date.now() }));
    const updatedUser = { ...currentUser, balance: currentUser.balance - total, orders: [...currentUser.orders, ...newOrders] };

    setUsers(prev => prev.map(u => u.email === updatedUser.email ? updatedUser : u));
    setCurrentUser(updatedUser);
    await dbService.saveUser(updatedUser);

    setCart([]); 
    setIsCartOpen(false); 
    setIsProcessingCheckout(false); 
    setCurrentView('profile');
    alert('Purchase confirmed!');
  };

  if (isLoadingDB) {
    return (
      <div className="h-screen w-screen flex flex-col items-center justify-center bg-white dark:bg-slate-950">
        <div className="relative w-24 h-24 mb-6">
          <div className="absolute inset-0 border-4 border-skyblue-100 dark:border-slate-800 rounded-full"></div>
          <div className="absolute inset-0 border-4 border-skyblue-500 rounded-full border-t-transparent animate-spin"></div>
          <div className="absolute inset-0 flex items-center justify-center text-skyblue-500">
            <i className="fa-solid fa-microchip text-2xl animate-pulse"></i>
          </div>
        </div>
        <h1 className="text-xl font-black text-slate-800 dark:text-white uppercase tracking-widest">NETTOOLZ Portal</h1>
        <p className="text-slate-400 dark:text-slate-500 text-sm mt-2 font-medium">Securing networking interface...</p>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex flex-col bg-white dark:bg-slate-950 transition-colors">
      <Navbar 
        cartCount={cart.reduce((acc, item) => acc + item.quantity, 0)} 
        isDarkMode={isDarkMode} 
        logoUrl={settings.logoUrl}
        currentUserEmail={currentUser?.email}
        onNavigate={setCurrentView} 
        onOpenCart={() => setIsCartOpen(true)} 
        onToggleTheme={() => { setIsDarkMode(!isDarkMode); document.documentElement.classList.toggle('dark'); }} 
      />

      {isGeneratingImages && (
        <div className="bg-skyblue-500 text-white text-[10px] font-black uppercase tracking-[0.2em] py-2 text-center animate-pulse">
          AI Assistant is generating high-quality product renders...
        </div>
      )}

      <main className="flex-1 max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 w-full py-8">
        {currentView === 'home' && (
          <div className="space-y-16">
            <section className="relative px-6 py-24 bg-gradient-to-br from-skyblue-50 to-white dark:from-slate-900 dark:to-slate-950 rounded-[2.5rem] border border-skyblue-100 dark:border-slate-800 overflow-hidden shadow-2xl shadow-skyblue-100 dark:shadow-none">
              <div className="absolute top-0 right-0 p-12 opacity-5 pointer-events-none">
                <i className="fa-solid fa-network-wired text-[20rem] text-skyblue-500"></i>
              </div>
              <div className="relative z-10 text-center max-w-4xl mx-auto">
                <span className="inline-block px-4 py-2 bg-skyblue-100 dark:bg-skyblue-900/30 text-skyblue-600 dark:text-skyblue-400 rounded-full text-[10px] font-black uppercase mb-8 tracking-[0.3em]">The Premier Networking Vault</span>
                <h1 className="text-6xl sm:text-7xl font-black text-slate-900 dark:text-white leading-[1.1] mb-8 tracking-tighter">
                  NET<span className="text-skyblue-500">TOOLZ</span> <br/> 
                  <span className="text-slate-400">Enterprise Suite</span>
                </h1>
                <p className="text-xl text-slate-500 dark:text-slate-400 mb-12 leading-relaxed font-medium">
                  Automated delivery of high-performance Proxies, VPNs, and Remote Desktops.
                </p>
                <div className="flex flex-col sm:flex-row items-center justify-center gap-4">
                  <button onClick={() => setCurrentView('category')} className="w-full sm:w-auto bg-skyblue-500 hover:bg-skyblue-600 text-white font-black px-12 py-5 rounded-2xl shadow-xl shadow-skyblue-200 dark:shadow-none transition-all active:scale-95 text-lg">
                    Browse Catalog
                  </button>
                  <button onClick={() => setCurrentView('profile')} className="w-full sm:w-auto bg-white dark:bg-slate-800 text-slate-900 dark:text-white border border-slate-200 dark:border-slate-700 font-black px-12 py-5 rounded-2xl transition-all hover:bg-slate-50 dark:hover:bg-slate-700 active:scale-95 text-lg">
                    Manage Wallet
                  </button>
                </div>
              </div>
            </section>

            <div className="flex items-center justify-between mb-8">
              <h2 className="text-3xl font-black dark:text-white tracking-tighter">Featured <span className="text-skyblue-500">Assets</span></h2>
              <button onClick={() => setCurrentView('category')} className="text-skyblue-500 font-bold hover:underline">View All &rarr;</button>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-8">
              {products.filter(p => p.isVisible).slice(0, 3).map(p => <ProductCard key={p.id} product={p} onAddToCart={addToCart} onViewDetails={(p) => { setSelectedProduct(p); setCurrentView('product'); }} />)}
            </div>
          </div>
        )}

        {currentView === 'category' && (
          <div className="py-8 flex flex-col md:flex-row gap-12">
            <aside className="w-full md:w-64 space-y-8">
              <div>
                <h3 className="text-sm font-black text-slate-400 uppercase tracking-widest mb-6">Store Navigation</h3>
                <div className="space-y-2">
                  <button onClick={() => setSelectedCategory(null)} className={`w-full text-left px-5 py-3.5 rounded-2xl transition-all font-bold ${!selectedCategory ? 'bg-skyblue-500 text-white shadow-xl shadow-skyblue-200 dark:shadow-none' : 'bg-white dark:bg-slate-900 text-slate-500 border border-transparent hover:border-skyblue-200'}`}>
                    All Categories
                  </button>
                  {settings.categories.map(cat => (
                    <button 
                      key={cat.id} 
                      onClick={() => setSelectedCategory(cat.id)} 
                      className={`w-full text-left px-5 py-3.5 rounded-2xl transition-all font-bold flex items-center space-x-3 ${selectedCategory === cat.id ? 'bg-skyblue-500 text-white shadow-xl shadow-skyblue-200 dark:shadow-none' : 'bg-white dark:bg-slate-900 text-slate-500 border border-transparent hover:border-skyblue-200 dark:hover:border-slate-800'}`}
                    >
                      <i className={`fa-solid ${cat.icon} w-5`}></i>
                      <span>{cat.name}</span>
                    </button>
                  ))}
                </div>
              </div>
            </aside>

            <div className="flex-1">
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-8">
                {products.filter(p => p.isVisible && (!selectedCategory || p.category === selectedCategory)).map(p => <ProductCard key={p.id} product={p} onAddToCart={addToCart} onViewDetails={(p) => { setSelectedProduct(p); setCurrentView('product'); }} />)}
              </div>
              {products.filter(p => p.isVisible && (!selectedCategory || p.category === selectedCategory)).length === 0 && (
                <div className="py-24 text-center">
                  <i className="fa-solid fa-magnifying-glass text-4xl text-slate-200 mb-4"></i>
                  <p className="text-slate-400 font-bold italic">No matching products found in this category.</p>
                </div>
              )}
            </div>
          </div>
        )}

        {currentView === 'product' && selectedProduct && (
          <div className="py-8 max-w-6xl mx-auto">
            <button onClick={() => setCurrentView('category')} className="mb-8 text-slate-400 font-bold hover:text-skyblue-500 flex items-center transition-colors">
              <i className="fa-solid fa-arrow-left-long mr-2"></i> Back to Catalog
            </button>
            <div className="bg-white dark:bg-slate-900 rounded-[3rem] p-10 border border-skyblue-100 dark:border-slate-800 flex flex-col md:flex-row gap-16 shadow-2xl shadow-skyblue-50 dark:shadow-none">
              <div className="flex-1 rounded-[2rem] overflow-hidden shadow-2xl bg-white dark:bg-slate-800 aspect-square">
                <img src={selectedProduct.image} className="w-full h-full object-cover" alt={selectedProduct.name} />
              </div>
              <div className="flex-1 flex flex-col justify-center space-y-8">
                <div className="space-y-2">
                  <span className="text-skyblue-500 font-black uppercase text-xs tracking-widest">{selectedProduct.category}</span>
                  <h1 className="text-5xl font-black dark:text-white leading-[1.1] tracking-tighter">{selectedProduct.name}</h1>
                </div>
                <div className="flex items-center space-x-4">
                  <p className="text-5xl font-black text-slate-900 dark:text-white">₦{selectedProduct.price.toLocaleString()}</p>
                  <div className="px-3 py-1 bg-green-100 text-green-600 rounded-full text-[10px] font-black uppercase tracking-widest">Instant Delivery</div>
                </div>
                <p className="text-lg text-slate-500 dark:text-slate-400 leading-relaxed font-medium">
                  {selectedProduct.description}
                </p>
                <div className="grid grid-cols-2 gap-4">
                  {selectedProduct.features.map((f, i) => (
                    <div key={i} className="flex items-center space-x-3 text-slate-600 dark:text-slate-300">
                      <div className="w-6 h-6 bg-skyblue-50 dark:bg-skyblue-900/20 text-skyblue-500 rounded-full flex items-center justify-center text-[10px]">
                        <i className="fa-solid fa-check"></i>
                      </div>
                      <span className="text-sm font-bold">{f}</span>
                    </div>
                  ))}
                </div>
                <button onClick={() => addToCart(selectedProduct)} className="w-full bg-skyblue-500 hover:bg-skyblue-600 text-white font-black py-5 rounded-[1.5rem] shadow-xl shadow-skyblue-200 dark:shadow-none transition-all active:scale-95 mt-8 text-lg flex items-center justify-center space-x-3">
                  <i className="fa-solid fa-cart-shopping"></i>
                  <span>Secure Checkout</span>
                </button>
              </div>
            </div>
          </div>
        )}

        {currentView === 'profile' && (
          currentUser ? (
