          <div className="relative w-full max-w-md bg-white dark:bg-slate-900 h-full p-10 flex flex-col shadow-[0_0_100px_rgba(14,165,233,0.1)] animate-in slide-in-from-right duration-500">
            <div className="flex items-center justify-between mb-12">
              <h2 className="text-4xl font-black dark:text-white tracking-tighter">Your <span className="text-skyblue-500">Cart</span></h2>
