            <div className="flex-1 overflow-y-auto space-y-6 custom-scrollbar pr-2">
              {cart.map(item => (
                <div key={item.id} className="flex gap-5 p-5 bg-skyblue-50/50 dark:bg-slate-800/50 rounded-3xl border border-skyblue-100 dark:border-slate-800 group">
                  <img src={item.image} className="w-20 h-20 rounded-2xl object-cover bg-white shadow-sm" alt={item.name} />
                  <div className="flex-1">
                    <p className="font-black dark:text-white text-lg leading-tight mb-1">{item.name}</p>
                    <div className="flex items-center justify-between mt-auto">
                      <p className="text-skyblue-600 dark:text-skyblue-400 font-black">₦{item.price.toLocaleString()}</p>
                      <div className="flex items-center space-x-3 bg-white dark:bg-slate-900 rounded-xl px-3 py-1 border border-skyblue-100">
                         <button onClick={() => {
                           if (item.quantity > 1) {
                             setCart(cart.map(i => i.id === item.id ? { ...i, quantity: i.quantity - 1 } : i));
                           } else {
                             setCart(cart.filter(i => i.id !== item.id));
                           }
                         }} className="text-slate-400 hover:text-skyblue-500"><i className="fa-solid fa-minus text-xs"></i></button>
                         <span className="font-black text-sm">{item.quantity}</span>
                         <button onClick={() => setCart(cart.map(i => i.id === item.id ? { ...i, quantity: i.quantity + 1 } : i))} className="text-slate-400 hover:text-skyblue-500"><i className="fa-solid fa-plus text-xs"></i></button>
                      </div>
                    </div>
                  </div>
                  <button onClick={() => setCart(cart.filter(i => i.id !== item.id))} className="text-slate-300 hover:text-red-500 transition-colors self-start"><i className="fa-solid fa-trash-can"></i></button>
                </div>
              ))}
              {cart.length === 0 && (
                <div className="text-center py-32 text-slate-300">
                  <div className="bg-slate-50 dark:bg-slate-800 w-24 h-24 rounded-full flex items-center justify-center mx-auto mb-6">
                    <i className="fa-solid fa-shopping-cart text-4xl"></i>
                  </div>
                  <p className="text-xl font-black uppercase tracking-widest mb-2">Cart Empty</p>
