              <div className="pt-10 border-t dark:border-slate-800 mt-auto">
                <div className="flex justify-between text-sm font-black text-slate-400 uppercase tracking-widest mb-2">
                  <span>Subtotal</span>
                  <span>₦{cart.reduce((a, i) => a + (i.price * i.quantity), 0).toLocaleString()}</span>
                </div>
                <div className="flex justify-between text-4xl font-black mb-10 dark:text-white tracking-tighter">
                  <span>Total</span>
