                  <div className="space-y-4 animate-in fade-in slide-in-from-top-2">
                     <div className="p-4 bg-sky-500/5 rounded-2xl border border-sky-500/20 space-y-4">
                        <div>
                          <label className="text-[10px] font-black text-sky-500 uppercase block mb-1">API Public Key</label>
                          <input type="text" value={editingPayment.apiPublicKey || ''} onChange={e => setEditingPayment({...editingPayment, apiPublicKey: e.target.value})} className="w-full bg-white dark:bg-slate-900 p-2 rounded-lg border border-sky-100 dark:border-slate-700 font-mono text-xs dark:text-white" placeholder="pk_live_..." />
                        </div>
                        <div>
                          <label className="text-[10px] font-black text-sky-500 uppercase block mb-1">API Secret Key</label>
                          <div className="relative">
                            <input type={showSecret ? "text" : "password"} value={editingPayment.apiSecretKey || ''} onChange={e => setEditingPayment({...editingPayment, apiSecretKey: e.target.value})} className="w-full bg-white dark:bg-slate-900 p-2 rounded-lg border border-sky-100 dark:border-slate-700 font-mono text-xs dark:text-white" placeholder="sk_live_..." />
                            <button type="button" onClick={() => setShowSecret(!showSecret)} className="absolute right-2 top-1.5 text-slate-300 hover:text-sky-500"><i className={`fa-solid ${showSecret ? 'fa-eye-slash' : 'fa-eye'}`}></i></button>
                          </div>
                        </div>
                        <div>
                          <label className="text-[10px] font-black text-sky-500 uppercase block mb-1">Merchant ID</label>
                          <input type="text" value={editingPayment.merchantId || ''} onChange={e => setEditingPayment({...editingPayment, merchantId: e.target.value})} className="w-full bg-white dark:bg-slate-900 p-2 rounded-lg border border-sky-100 dark:border-slate-700 font-mono text-xs dark:text-white" placeholder="MER-..." />
                        </div>

                        <div className="pt-2">
                           <button 
                            type="button" 
                            onClick={testApiConnection}
                            disabled={isTestingApi}
                            className="w-full py-2 bg-slate-900 dark:bg-slate-950 text-white text-[10px] font-black rounded-lg hover:bg-black transition-all flex items-center justify-center space-x-2 active:scale-95"
                           >
                             {isTestingApi ? <i className="fa-solid fa-spinner animate-spin"></i> : <i className="fa-solid fa-vial"></i>}
                             <span>{isTestingApi ? 'TESTING...' : 'RUN CONNECTIVITY TEST'}</span>
                           </button>
                           {apiTestResult && (
                             <p className={`mt-2 text-[10px] font-bold text-center ${apiTestResult.includes('Stable') ? 'text-green-500' : 'text-red-500'}`}>
                               {apiTestResult}
                             </p>
                           )}
                        </div>
                     </div>
                  </div>
                )}

                <div className="flex justify-end space-x-3 pt-6">
                  <button type="button" onClick={() => setEditingPayment(null)} className="px-6 py-2 text-slate-400 font-bold uppercase tracking-widest text-xs">Cancel</button>
                  <button type="submit" className="px-8 py-3 bg-sky-500 text-white font-black rounded-xl shadow-lg active:scale-95 transition-all">Save Changes</button>
                </div>
             </form>
          </div>
        </div>
      )}

      {/* Category Edit Modal */}
      {editingCategory && (
        <div className="fixed inset-0 z-[700] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-900/80 backdrop-blur-sm" onClick={() => setEditingCategory(null)}></div>
          <div className="relative bg-white dark:bg-slate-900 w-full max-w-lg rounded-3xl shadow-2xl p-8 border border-sky-200 dark:border-slate-700 animate-in zoom-in-95">
             <h3 className="text-2xl font-black mb-6 dark:text-white">Edit Category</h3>
             <form onSubmit={handleSaveCategoryEdit} className="space-y-4">
                <div>
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1 block">Name</label>
                  <input type="text" value={editingCategory.name} onChange={e => setEditingCategory({...editingCategory, name: e.target.value})} className="w-full bg-sky-50 dark:bg-slate-800 p-3 rounded-xl border border-sky-100 dark:border-slate-700 dark:text-white" />
                </div>
                <div>
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1 block">Icon</label>
                  <input type="text" value={editingCategory.icon} onChange={e => setEditingCategory({...editingCategory, icon: e.target.value})} className="w-full bg-sky-50 dark:bg-slate-800 p-3 rounded-xl border border-sky-100 dark:border-slate-700 dark:text-white" />
                </div>
                <div className="flex justify-end space-x-3 pt-4">
                  <button type="button" onClick={() => setEditingCategory(null)} className="px-6 py-2 text-slate-400 font-bold uppercase text-xs">Cancel</button>
                  <button type="submit" className="bg-sky-500 text-white font-black px-10 py-3 rounded-xl shadow-lg">Update</button>
                </div>
             </form>
          </div>
        </div>
      )}

      {/* Individual Product Delete Modal */}
      {productToDelete && (
        <div className="fixed inset-0 z-[400] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-900/90 backdrop-blur-sm" onClick={() => setProductToDelete(null)}></div>
          <div className="relative bg-white dark:bg-slate-900 w-full max-w-sm rounded-3xl shadow-2xl p-8 border border-red-100 text-center animate-in zoom-in-95">
            <h3 className="text-xl font-black mb-2 dark:text-white">Delete Product?</h3>
            <p className="text-slate-500 text-sm mb-8 leading-relaxed">
              Are you sure you want to delete <span className="font-bold">"{productToDelete.name}"</span>?
            </p>
            <div className="flex gap-3">
              <button onClick={() => setProductToDelete(null)} className="flex-1 py-3 px-4 border-2 border-slate-100 text-sm font-bold rounded-xl text-slate-500">Keep it</button>
              <button onClick={() => { onUpdateProducts(products.filter(p => p.id !== productToDelete.id)); setProductToDelete(null); }} className="flex-1 py-3 px-4 bg-red-500 text-white text-sm font-bold rounded-xl transition-all active:scale-95">Delete</button>
            </div>
          </div>
        </div>
      )}

      {/* Individual Category Delete Modal */}
      {categoryToDelete && (
        <div className="fixed inset-0 z-[400] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-900/90 backdrop-blur-sm" onClick={() => setCategoryToDelete(null)}></div>
          <div className="relative bg-white dark:bg-slate-900 w-full max-w-sm rounded-3xl shadow-2xl p-8 border border-red-100 text-center animate-in zoom-in-95">
            <h3 className="text-xl font-black mb-2 dark:text-white">Delete Category?</h3>
            <p className="text-slate-500 text-sm mb-8 leading-relaxed">
              Deleting <span className="font-bold">"{categoryToDelete.name}"</span> will remove it from navigation.
            </p>
            <div className="flex gap-3">
              <button onClick={() => setCategoryToDelete(null)} className="flex-1 py-3 px-4 border-2 border-slate-100 text-sm font-bold rounded-xl text-slate-500">Cancel</button>
              <button onClick={() => { onUpdateSettings({ ...settings, categories: settings.categories.filter(c => c.id !== categoryToDelete.id) }); setCategoryToDelete(null); }} className="flex-1 py-3 px-4 bg-red-500 text-white text-sm font-bold rounded-xl">Delete</button>
            </div>
          </div>
        </div>
      )}

      {/* Product Edit Modal */}
      {editingProduct && (
        <div className="fixed inset-0 z-[300] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-900/90 backdrop-blur-sm" onClick={() => setEditingProduct(null)}></div>
          <div className="relative bg-white dark:bg-slate-900 w-full max-w-2xl rounded-3xl shadow-2xl p-8 border border-sky-100 dark:border-slate-800 animate-in zoom-in-95 duration-200">
            <h3 className="text-2xl font-black mb-6 dark:text-white">Edit Product</h3>
            <form onSubmit={handleSaveProductEdit} className="grid grid-cols-1 md:grid-cols-2 gap-6 max-h-[70vh] overflow-y-auto px-1 transition-colors">
              <div className="md:col-span-2 flex items-center space-x-6 mb-2">
                <div className="w-24 h-24 rounded-xl bg-sky-50 dark:bg-slate-950 border border-sky-100 dark:border-slate-800 flex items-center justify-center overflow-hidden transition-colors">
                  <img src={editingProduct.image} className="w-full h-full object-cover" />
                </div>
                <div>
                   <input type="file" ref={editFileInputRef} onChange={(e) => handleImageUpload(e, true)} className="hidden" accept="image/*" />
                   <button type="button" onClick={() => editFileInputRef.current?.click()} className="bg-sky-500 text-white text-xs font-black px-4 py-2 rounded-lg shadow transition-all active:scale-95">Change Photo</button>
                </div>
              </div>
              <div>
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1 block">Name</label>
                <input type="text" value={editingProduct.name} onChange={e => setEditingProduct({...editingProduct, name: e.target.value})} className="w-full bg-sky-50 dark:bg-slate-800 p-3 rounded-xl border border-sky-100 dark:border-slate-700 dark:text-white" />
              </div>
              <div>
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1 block">Category</label>
                <select value={editingProduct.category} onChange={e => setEditingProduct({...editingProduct, category: e.target.value})} className="w-full bg-sky-50 dark:bg-slate-800 p-3 rounded-xl border border-sky-100 dark:border-slate-700 dark:text-white">
                  {settings.categories.map(cat => <option key={cat.id} value={cat.id}>{cat.name}</option>)}
                </select>
              </div>
              <div>
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1 block">Price</label>
                <input type="number" value={editingProduct.price} onChange={e => setEditingProduct({...editingProduct, price: Number(e.target.value)})} className="w-full bg-sky-50 dark:bg-slate-800 p-3 rounded-xl border border-sky-100 dark:border-slate-700 dark:text-white" />
              </div>
              <div>
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1 block">Stock</label>
                <input type="number" value={editingProduct.stock} onChange={e => setEditingProduct({...editingProduct, stock: Number(e.target.value)})} className="w-full bg-sky-50 dark:bg-slate-800 p-3 rounded-xl border border-sky-100 dark:border-slate-700 dark:text-white" />
              </div>
              <div className="md:col-span-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1 block">Secret Content</label>
                <textarea value={editingProduct.secretContent} onChange={e => setEditingProduct({...editingProduct, secretContent: e.target.value})} className="w-full bg-sky-50 dark:bg-slate-800 p-3 rounded-xl border border-sky-100 dark:border-slate-700 dark:text-white font-mono h-24" />
              </div>
              <div className="md:col-span-2 flex justify-end space-x-3 pt-4">
                <button type="button" onClick={() => setEditingProduct(null)} className="px-6 py-2 text-slate-400 font-bold uppercase tracking-widest text-xs">Cancel</button>
                <button type="submit" className="bg-sky-500 text-white font-black px-10 py-3 rounded-xl shadow-lg transition-all active:scale-95">Update Product</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminDashboard;

import React, { useState, useRef } from 'react';
import { Product, Category, SiteSettings, AdminUser, PaymentMethod } from '../types';
import { paymentService } from '../services/paymentService';
import { GoogleGenAI } from "@google/genai";

interface AdminDashboardProps {
  products: Product[];
  settings: SiteSettings;
  admins: AdminUser[];
  onUpdateProducts: (newProducts: Product[]) => void;
  onUpdateSettings: (newSettings: SiteSettings) => void;
  onUpdateAdmins: (newAdmins: AdminUser[]) => void;
  onLogout: () => void;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ 
  products, settings, admins, onUpdateProducts, onUpdateSettings, onUpdateAdmins, onLogout 
}) => {
  const [activeTab, setActiveTab] = useState<'products' | 'categories' | 'settings' | 'admins' | 'payments'>('products');
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);
  const [editingCategory, setEditingCategory] = useState<Category | null>(null);
  const [editingPayment, setEditingPayment] = useState<PaymentMethod | null>(null);
  const [productToDelete, setProductToDelete] = useState<Product | null>(null);
  const [categoryToDelete, setCategoryToDelete] = useState<Category | null>(null);
  const [adminToDelete, setAdminToDelete] = useState<AdminUser | null>(null);
  const [showCreateForm, setShowCreateForm] = useState(false);
  const [showCategoryForm, setShowCategoryForm] = useState(false);
  const [showAdminForm, setShowAdminForm] = useState(false);
  const [isTestingApi, setIsTestingApi] = useState(false);
  const [apiTestResult, setApiTestResult] = useState<string | null>(null);
  const [showSecret, setShowSecret] = useState(false);

  // Bulk & Global Actions State
  const [selectedProductIds, setSelectedProductIds] = useState<string[]>([]);
  const [showBulkDeleteConfirm, setShowBulkDeleteConfirm] = useState(false);
  const [showBulkCategoryModal, setShowBulkCategoryModal] = useState(false);
  const [bulkCategoryTarget, setBulkCategoryTarget] = useState<string>(settings.categories[0]?.id || '');

  // Logo Generation State
  const [isGeneratingLogo, setIsGeneratingLogo] = useState(false);
  const [tempLogoUrl, setTempLogoUrl] = useState<string | null>(null);

  const editFileInputRef = useRef<HTMLInputElement>(null);

  // Form states
  const [newProduct, setNewProduct] = useState({
    name: '', description: '', price: '', category: settings.categories[0]?.id || '',
    stock: '', image: '', features: '', secretContent: ''
  });

  const [newCategory, setNewCategory] = useState({ name: '', icon: 'fa-box' });
  const [newAdmin, setNewAdmin] = useState({ username: '', role: 'editor' as 'super' | 'editor' });

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>, isEdit = false) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64 = reader.result as string;
        if (isEdit && editingProduct) setEditingProduct({ ...editingProduct, image: base64 });
        else setNewProduct({ ...newProduct, image: base64 });
      };
      reader.readAsDataURL(file);
    }
  };

  const handleCreateProduct = (e: React.FormEvent) => {
    e.preventDefault();
    const product: Product = {
      id: Date.now().toString(),
      name: newProduct.name,
      description: newProduct.description,
      price: parseFloat(newProduct.price),
      category: newProduct.category,
      stock: parseInt(newProduct.stock),
      rating: 5.0,
      image: newProduct.image || 'https://picsum.photos/seed/tool/400/300',
      features: newProduct.features.split(',').map(f => f.trim()).filter(f => f !== ''),
      isVisible: true,
      secretContent: newProduct.secretContent
    };
    onUpdateProducts([product, ...products]);
    setShowCreateForm(false);
    setNewProduct({ name: '', description: '', price: '', category: settings.categories[0]?.id || '', stock: '', image: '', features: '', secretContent: '' });
  };

  const handleSaveProductEdit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingProduct) return;
    onUpdateProducts(products.map(p => p.id === editingProduct.id ? editingProduct : p));
    setEditingProduct(null);
  };

  // Bulk Operations
  const toggleSelectAll = () => {
    if (selectedProductIds.length === products.length && products.length > 0) {
      setSelectedProductIds([]);
    } else {
      setSelectedProductIds(products.map(p => p.id));
    }
  };

  const toggleSelectProduct = (id: string) => {
    setSelectedProductIds(prev => 
      prev.includes(id) ? prev.filter(pId => pId !== id) : [...prev, id]
    );
  };

  const bulkUpdateVisibility = (visible: boolean) => {
    onUpdateProducts(products.map(p => 
      selectedProductIds.includes(p.id) ? { ...p, isVisible: visible } : p
    ));
    setSelectedProductIds([]);
  };

  const bulkDeleteProducts = () => {
    onUpdateProducts(products.filter(p => !selectedProductIds.includes(p.id)));
    setSelectedProductIds([]);
    setShowBulkDeleteConfirm(false);
  };

  const bulkUpdateCategory = () => {
    onUpdateProducts(products.map(p => 
      selectedProductIds.includes(p.id) ? { ...p, category: bulkCategoryTarget } : p
    ));
    setSelectedProductIds([]);
    setShowBulkCategoryModal(false);
  };

  const bulkUpdateStock = (amount: number) => {
    onUpdateProducts(products.map(p => 
      selectedProductIds.includes(p.id) ? { ...p, stock: Math.max(0, p.stock + amount) } : p
    ));
  };

  // Logo & Branding
  const generateLogo = async () => {
    setIsGeneratingLogo(true);
    setTempLogoUrl(null);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = `A modern and professional logo for "NETTOOLZ", an e-commerce platform for high-quality digital tools. Sky-blue aesthetic, networking nodes, minimalist, high-end feel. White background.`;

      const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: { parts: [{ text: prompt }] },
      });

      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData) {
          setTempLogoUrl(`data:image/png;base64,${part.inlineData.data}`);
          break;
        }
      }
    } catch (error) {
      console.error("Logo generation failed:", error);
    } finally {
      setIsGeneratingLogo(false);
    }
  };

  const handleCreateCategory = (e: React.FormEvent) => {
    e.preventDefault();
    const cat: Category = {
      id: newCategory.name.toLowerCase().replace(/\s+/g, '-'),
      name: newCategory.name,
      icon: newCategory.icon
    };
    onUpdateSettings({ ...settings, categories: [...settings.categories, cat] });
    setShowCategoryForm(false);
    setNewCategory({ name: '', icon: 'fa-box' });
  };

  const handleSaveCategoryEdit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingCategory) return;
    onUpdateSettings({
      ...settings,
      categories: settings.categories.map(c => c.id === editingCategory.id ? editingCategory : c)
    });
    setEditingCategory(null);
  };

  const handleCreateAdmin = (e: React.FormEvent) => {
    e.preventDefault();
    const admin: AdminUser = {
      id: Date.now().toString(),
      username: newAdmin.username,
      role: newAdmin.role
    };
    onUpdateAdmins([...admins, admin]);
    setShowAdminForm(false);
    setNewAdmin({ username: '', role: 'editor' });
  };

  const handleSavePayment = (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingPayment) return;
    const methods = settings.paymentMethods.map(m => m.id === editingPayment.id ? editingPayment : m);
    onUpdateSettings({ ...settings, paymentMethods: methods });
    setEditingPayment(null);
  };

  return (
    <div className="flex flex-col md:flex-row min-h-[85vh] bg-white dark:bg-slate-900 rounded-[2.5rem] border border-skyblue-100 dark:border-slate-800 overflow-hidden shadow-[0_20px_50px_rgba(14,165,233,0.05)] mb-12 transition-all">
      {/* Sidebar Navigation */}
      <div className="w-full md:w-72 bg-slate-900 p-10 shrink-0 flex flex-col">
        <div className="flex items-center space-x-3 mb-16">
          <div className="bg-skyblue-500 p-2 rounded-xl text-white shadow-lg shadow-skyblue-500/20">
            <i className="fa-solid fa-gauge-high"></i>
          </div>
          <h2 className="text-xl font-black text-white tracking-tighter uppercase">NetToolz Control</h2>
        </div>

        <nav className="space-y-3 flex-1">
          <button onClick={() => setActiveTab('products')} className={`w-full text-left px-5 py-4 rounded-2xl font-bold flex items-center space-x-4 transition-all ${activeTab === 'products' ? 'bg-skyblue-500 text-white shadow-xl shadow-skyblue-500/20' : 'text-slate-400 hover:text-white hover:bg-white/5'}`}>
            <i className="fa-solid fa-cube w-5"></i><span>Inventory</span>
          </button>
          <button onClick={() => setActiveTab('categories')} className={`w-full text-left px-5 py-4 rounded-2xl font-bold flex items-center space-x-4 transition-all ${activeTab === 'categories' ? 'bg-skyblue-500 text-white shadow-xl shadow-skyblue-500/20' : 'text-slate-400 hover:text-white hover:bg-white/5'}`}>
            <i className="fa-solid fa-tags w-5"></i><span>Categories</span>
          </button>
          <button onClick={() => setActiveTab('admins')} className={`w-full text-left px-5 py-4 rounded-2xl font-bold flex items-center space-x-4 transition-all ${activeTab === 'admins' ? 'bg-skyblue-500 text-white shadow-xl shadow-skyblue-500/20' : 'text-slate-400 hover:text-white hover:bg-white/5'}`}>
            <i className="fa-solid fa-user-shield w-5"></i><span>Staff Portal</span>
          </button>
          <button onClick={() => setActiveTab('payments')} className={`w-full text-left px-5 py-4 rounded-2xl font-bold flex items-center space-x-4 transition-all ${activeTab === 'payments' ? 'bg-skyblue-500 text-white shadow-xl shadow-skyblue-500/20' : 'text-slate-400 hover:text-white hover:bg-white/5'}`}>
            <i className="fa-solid fa-code w-5"></i><span>API Integrations</span>
          </button>
          <button onClick={() => setActiveTab('settings')} className={`w-full text-left px-5 py-4 rounded-2xl font-bold flex items-center space-x-4 transition-all ${activeTab === 'settings' ? 'bg-skyblue-500 text-white shadow-xl shadow-skyblue-500/20' : 'text-slate-400 hover:text-white hover:bg-white/5'}`}>
            <i className="fa-solid fa-sliders w-5"></i><span>Site Config</span>
          </button>
        </nav>

        <button onClick={onLogout} className="mt-12 w-full text-left px-5 py-4 text-red-400 font-bold hover:bg-red-500/10 rounded-2xl transition-all">
          <i className="fa-solid fa-power-off mr-3"></i><span>Secure Logout</span>
        </button>
      </div>

      {/* Main Content Area */}
      <div className="flex-1 p-10 bg-skyblue-50/10 dark:bg-slate-900/40 overflow-y-auto custom-scrollbar">
        <header className="flex flex-col sm:flex-row justify-between items-start sm:items-center mb-12 gap-6">
          <div>
            <h3 className="text-4xl font-black dark:text-white tracking-tighter capitalize">{activeTab}</h3>
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.3em] mt-2">Enterprise Management Unit</p>
          </div>

          <div className="flex items-center space-x-3">
            {activeTab === 'products' && (
              <button 
                onClick={() => setShowCreateForm(!showCreateForm)}
                className={`flex items-center space-x-3 font-black px-8 py-4 rounded-2xl shadow-xl transition-all active:scale-95 ${showCreateForm ? 'bg-slate-800 text-white' : 'bg-skyblue-500 text-white shadow-skyblue-500/20'}`}
              >
                <i className={`fa-solid ${showCreateForm ? 'fa-xmark' : 'fa-plus'}`}></i>
                <span>{showCreateForm ? 'Discard' : 'Deploy New Asset'}</span>
              </button>
            )}
            {activeTab === 'categories' && (
              <button onClick={() => setShowCategoryForm(true)} className="bg-skyblue-500 text-white font-black px-8 py-4 rounded-2xl shadow-xl shadow-skyblue-500/20 transition-all active:scale-95">
                <i className="fa-solid fa-folder-plus mr-2"></i>New Segment
              </button>
            )}
            {activeTab === 'admins' && (
              <button onClick={() => setShowAdminForm(true)} className="bg-skyblue-500 text-white font-black px-8 py-4 rounded-2xl shadow-xl shadow-skyblue-500/20 transition-all active:scale-95">
                <i className="fa-solid fa-user-plus mr-2"></i>Provision Account
              </button>
            )}
          </div>
        </header>

        {/* Tab: Products */}
        {activeTab === 'products' && (
          <div className="space-y-8 animate-in fade-in duration-500">
            {showCreateForm && (
               <form onSubmit={handleCreateProduct} className="bg-white dark:bg-slate-800 p-10 rounded-[2.5rem] border border-skyblue-100 dark:border-slate-700 shadow-2xl space-y-6 animate-in slide-in-from-top-4">
