              {cart.length === 0 && (
                <div className="text-center py-32 text-slate-300">
                  <div className="bg-slate-50 dark:bg-slate-800 w-24 h-24 rounded-full flex items-center justify-center mx-auto mb-6">
                    <i className="fa-solid fa-shopping-cart text-4xl"></i>
                  </div>
                  <p className="text-xl font-black uppercase tracking-widest mb-2">Cart Empty</p>
                  <p className="text-sm font-medium">Add some assets to get started.</p>
                </div>
              )}
            </div>

            {cart.length > 0 && (
              <div className="pt-10 border-t dark:border-slate-800 mt-auto">
                <div className="flex justify-between text-sm font-black text-slate-400 uppercase tracking-widest mb-2">
                  <span>Subtotal</span>
                  <span>₦{cart.reduce((a, i) => a + (i.price * i.quantity), 0).toLocaleString()}</span>
                </div>
                <div className="flex justify-between text-4xl font-black mb-10 dark:text-white tracking-tighter">
                  <span>Total</span>
                  <span className="text-skyblue-500">₦{cart.reduce((a, i) => a + (i.price * i.quantity), 0).toLocaleString()}</span>
                </div>
                <button onClick={handleCheckout} disabled={isProcessingCheckout} className="w-full bg-skyblue-500 text-white font-black py-5 rounded-[1.5rem] shadow-2xl shadow-skyblue-200 dark:shadow-none hover:bg-skyblue-600 transition-all active:scale-95 disabled:bg-slate-300 flex items-center justify-center space-x-3">
                  {isProcessingCheckout ? (
                    <><i className="fa-solid fa-spinner animate-spin"></i><span>Securing Transaction...</span></>
                  ) : (
                    <><i className="fa-solid fa-lock"></i><span>Checkout with Wallet</span></>
                  )}
