      <footer className="bg-white dark:bg-slate-950 border-t border-slate-100 dark:border-slate-900 py-16 text-center transition-colors">
        <div className="max-w-7xl mx-auto px-4">
          <div className="flex flex-col items-center mb-10">
            <div className="text-3xl font-black tracking-tighter text-slate-900 dark:text-white mb-4">
              NET<span className="text-skyblue-500">TOOLZ</span>
            </div>
            <p className="text-slate-400 font-medium max-w-sm">The world's most trusted source for premium digital assets and enterprise networking tools.</p>
          </div>
          <div className="flex justify-center space-x-6 mb-12">
            <a href="#" className="text-slate-400 hover:text-skyblue-500 transition-colors text-xl"><i className="fa-brands fa-telegram"></i></a>
            <a href="#" className="text-slate-400 hover:text-skyblue-500 transition-colors text-xl"><i className="fa-brands fa-discord"></i></a>
            <a href="#" className="text-slate-400 hover:text-skyblue-500 transition-colors text-xl"><i className="fa-brands fa-x-twitter"></i></a>
          </div>
          <div className="pt-8 border-t border-slate-50 dark:border-slate-900">
             <p className="text-slate-300 text-[10px] font-black uppercase tracking-[0.3em]">© 2024 NETTOOLZ Enterprise. All Rights Reserved. Encrypted by Gemini.</p>
             <button onClick={() => setCurrentView('admin_login')} className="mt-6 text-[10px] text-slate-300 hover:text-skyblue-500 font-black tracking-widest transition-colors opacity-30 hover:opacity-100">SYSTEM ACCESS</button>
          </div>
        </div>
      </footer>
      <GeminiAssistant />
    </div>
  );
};

