import React, { useState, useEffect, useCallback } from 'react';
import { Product, CartItem, ViewState, SiteSettings, AdminUser, User, UserOrder } from './types';
import { INITIAL_PRODUCTS, CATEGORIES } from './constants';
import { dbService } from './services/dbService';
import { generateProductImage } from './services/geminiService';
import Navbar from './components/Navbar';
import ProductCard from './components/ProductCard';
import GeminiAssistant from './components/GeminiAssistant';
import AdminLogin from './components/AdminLogin';
import AdminDashboard from './components/AdminDashboard';
import UserAuth from './components/UserAuth';
import UserProfile from './components/UserProfile';
import WalletFunding from './components/WalletFunding';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<ViewState>('home');
  const [selectedCategory, setSelectedCategory] = useState<string | null>(null);
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [isProcessingCheckout, setIsProcessingCheckout] = useState(false);
  const [isLoadingDB, setIsLoadingDB] = useState(true);
  const [isGeneratingImages, setIsGeneratingImages] = useState(false);

  const [products, setProducts] = useState<Product[]>([]);
  const [admins, setAdmins] = useState<AdminUser[]>([{ id: '1', username: 'Admin', role: 'super' }]);
  const [settings, setSettings] = useState<SiteSettings>({
    currency: 'NGN',
    currencySymbol: '₦',
    storeName: 'NETTOOLZ',
    usdtToNairaRate: 1650, 
    geminiApiKey: '',
    categories: CATEGORIES,
    paymentMethods: [
      { 
        id: 'bank1', 
        type: 'bank', 
        name: 'KoralPay (Automated Bank)', 
        details: 'Transfer to the virtual account generated at checkout.', 
        isActive: true,
        isAutomated: true,
        apiPublicKey: 'pk_live_nettoolz_7721',
        merchantId: 'MER-88122'
      },
      { 
        id: 'crypto1', 
        type: 'crypto', 
        name: 'Crypto (Instant Credit)', 
        details: 'Payment credits after 1 network confirmation.', 
        walletAddress: 'TYxxxxxxxxxxxxxxxxxxxxxx',
        network: 'TRC20',
        isActive: true,
        isAutomated: true,
        apiPublicKey: 'pk_live_crypto_9921',
        merchantId: 'MER-99123'
      }
    ]
  });
  const [isAdminLoggedIn, setIsAdminLoggedIn] = useState(false);
  const [users, setUsers] = useState<User[]>([]);
  const [currentUser, setCurrentUser] = useState<User | null>(null);

  const autoGenerateMissingImages = useCallback(async (currentProducts: Product[]) => {
    const productsToUpdate = currentProducts.filter(p => p.image.includes('picsum.photos'));
    if (productsToUpdate.length === 0) return;

    setIsGeneratingImages(true);
    const updatedProducts = [...currentProducts];

    for (let i = 0; i < productsToUpdate.length; i++) {
      const p = productsToUpdate[i];
      const newImage = await generateProductImage(p);
      if (newImage) {
        const index = updatedProducts.findIndex(item => item.id === p.id);
        if (index !== -1) {
          updatedProducts[index] = { ...updatedProducts[index], image: newImage };
        }
      }
    }

    setProducts(updatedProducts);
    await dbService.saveProducts(updatedProducts);
    setIsGeneratingImages(false);
  }, []);

  useEffect(() => {
    const initApp = async () => {
      try {
        await dbService.init();

        const savedSettings = await dbService.getSettings();
        if (savedSettings) setSettings(savedSettings);
        else await dbService.saveSettings(settings);

        const savedProducts = await dbService.getAllProducts();
        let currentProductsList = [];
        if (savedProducts && savedProducts.length > 0) {
          currentProductsList = savedProducts;
        } else {
          await dbService.saveProducts(INITIAL_PRODUCTS);
          currentProductsList = INITIAL_PRODUCTS;
        }
        setProducts(currentProductsList);

        const savedAdmins = await dbService.getAllAdmins();
        if (savedAdmins && savedAdmins.length > 0) setAdmins(savedAdmins);
        else await dbService.saveAdmins(admins);

        const savedUsers = await dbService.getAllUsers();
        setUsers(savedUsers);

        const savedAdmin = localStorage.getItem('nettoolz_admin_logged');
        if (savedAdmin === 'true') setIsAdminLoggedIn(true);

        const loggedUserEmail = localStorage.getItem('nettoolz_logged_user_email');
        if (loggedUserEmail) {
          const found = savedUsers.find(u => u.email === loggedUserEmail);
          if (found) setCurrentUser(found);
        }

        autoGenerateMissingImages(currentProductsList);

      } catch (err) {
        console.error("Database initialization failed:", err);
      } finally {
        setIsLoadingDB(false);
      }
    };

    initApp();
  }, [autoGenerateMissingImages]);

  const handleUpdateProducts = async (newProducts: Product[]) => {
    setProducts(newProducts);
    await dbService.saveProducts(newProducts);
  };

  const handleUpdateSettings = async (newSettings: SiteSettings) => {
    setSettings(newSettings);
    await dbService.saveSettings(newSettings);
  };

  const handleUpdateAdmins = async (newAdmins: AdminUser[]) => {
    setAdmins(newAdmins);
    await dbService.saveAdmins(newAdmins);
  };

  const handleAuth = async (user: User) => {
    const exists = users.find(u => u.email === user.email);
    const updatedUsers = exists 
      ? users.map(u => u.email === user.email ? user : u) 
      : [...users, user];

    setUsers(updatedUsers);
    setCurrentUser(user);
    await dbService.saveUser(user);
    localStorage.setItem('nettoolz_logged_user_email', user.email);
    setCurrentView('profile');
  };

  const handleFundSuccess = async (amount: number) => {
    if (!currentUser) return;
    const updatedUser = {
      ...currentUser,
      balance: currentUser.balance + amount
    };
    setUsers(prev => prev.map(u => u.email === updatedUser.email ? updatedUser : u));
    setCurrentUser(updatedUser);
    await dbService.saveUser(updatedUser);
  };

  const addToCart = (product: Product) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) return prev.map(item => item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item);
      return [...prev, { ...product, quantity: 1 }];
    });
    setIsCartOpen(true);
  };

  const handleCheckout = async () => {
    if (!currentUser) { setCurrentView('profile'); setIsCartOpen(false); return; }
    const total = cart.reduce((acc, item) => acc + (item.price * item.quantity), 0);
    if (currentUser.balance < total) { alert('Insufficient balance.'); setCurrentView('fund_wallet'); setIsCartOpen(false); return; }

    setIsProcessingCheckout(true);
    await new Promise(resolve => setTimeout(resolve, 1500));
    const newOrders: UserOrder[] = cart.map(item => ({ id: Date.now().toString() + Math.random(), productId: item.id, productName: item.name, content: item.secretContent || 'Processing...', price: item.price, timestamp: Date.now() }));
    const updatedUser = { ...currentUser, balance: currentUser.balance - total, orders: [...currentUser.orders, ...newOrders] };

    setUsers(prev => prev.map(u => u.email === updatedUser.email ? updatedUser : u));
    setCurrentUser(updatedUser);
    await dbService.saveUser(updatedUser);

    setCart([]); 
    setIsCartOpen(false); 
    setIsProcessingCheckout(false); 
    setCurrentView('profile');
    alert('Purchase confirmed!');
  };

  const renderProductList = (categoryItems: Product[], categoryName: string) => {
    if (categoryItems.length === 0) return null;
    return (
      <div className="mb-12">
        {/* Category Header Bar */}
        <div className="bg-gradient-to-r from-orange-600 via-pink-600 to-purple-800 rounded-t-[2rem] p-6 flex items-center justify-between text-white shadow-xl">
          <div className="flex items-center space-x-3">
            <h2 className="text-sm sm:text-lg font-black uppercase tracking-widest">{categoryName.replace("&#039;", "'")}</h2>
            <div className="bg-white/20 px-3 py-1 rounded-full text-xs font-black min-w-[32px] text-center">
              {categoryItems.length}
            </div>
          </div>
          <div className="flex items-center space-x-2">
            <button className="w-10 h-10 bg-white/10 hover:bg-white/20 rounded-xl flex items-center justify-center transition-colors">
              <i className="fa-solid fa-chevron-down text-sm"></i>
            </button>
            <button 
              onClick={() => { setSelectedCategory(categoryItems[0].category); setCurrentView('category'); }}
              className="bg-white/10 hover:bg-white/20 px-4 py-2 rounded-xl text-xs font-black uppercase flex items-center space-x-2 transition-colors"
            >
              <span>View All</span>
              <i className="fa-solid fa-arrow-right"></i>
            </button>
          </div>
        </div>

        {/* Category Items Container */}
        <div className="bg-white dark:bg-slate-900/50 border-x border-b border-slate-100 dark:border-slate-800 rounded-b-[2rem] p-6 space-y-2 shadow-sm">
          {categoryItems.map(p => (
            <ProductCard 
              key={p.id} 
              product={p} 
              onAddToCart={addToCart} 
              onViewDetails={(p) => { setSelectedProduct(p); setCurrentView('product'); }} 
            />
          ))}
        </div>
      </div>
    );
  };

  if (isLoadingDB) {
    return (
      <div className="h-screen w-screen flex flex-col items-center justify-center bg-white dark:bg-slate-950">
        <div className="relative w-24 h-24 mb-6">
          <div className="absolute inset-0 border-4 border-skyblue-100 dark:border-slate-800 rounded-full"></div>
          <div className="absolute inset-0 border-4 border-skyblue-500 rounded-full border-t-transparent animate-spin"></div>
          <div className="absolute inset-0 flex items-center justify-center text-skyblue-500">
            <i className="fa-solid fa-microchip text-2xl animate-pulse"></i>
          </div>
        </div>
        <h1 className="text-xl font-black text-slate-800 dark:text-white uppercase tracking-widest">NETTOOLZ Portal</h1>
        <p className="text-slate-400 dark:text-slate-500 text-sm mt-2 font-medium">Securing networking interface...</p>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex flex-col bg-slate-50 dark:bg-slate-950 transition-colors">
      <Navbar 
        cartCount={cart.reduce((acc, item) => acc + item.quantity, 0)} 
        isDarkMode={isDarkMode} 
        logoUrl={settings.logoUrl}
        currentUserEmail={currentUser?.email}
        onNavigate={setCurrentView} 
        onOpenCart={() => setIsCartOpen(true)} 
        onToggleTheme={() => { setIsDarkMode(!isDarkMode); document.documentElement.classList.toggle('dark'); }} 
      />

      {isGeneratingImages && (
        <div className="bg-skyblue-500 text-white text-[10px] font-black uppercase tracking-[0.2em] py-2 text-center animate-pulse">
          AI Assistant is generating high-quality product renders...
        </div>
      )}

      <main className="flex-1 max-w-5xl mx-auto px-4 sm:px-6 lg:px-8 w-full py-8">
        {currentView === 'home' && (
          <div className="space-y-12">
            <section className="relative px-6 py-20 bg-gradient-to-br from-white to-slate-50 dark:from-slate-900 dark:to-slate-950 rounded-[3rem] border border-slate-100 dark:border-slate-800 overflow-hidden shadow-2xl">
              <div className="relative z-10 text-center max-w-3xl mx-auto">
                <span className="inline-block px-4 py-1.5 bg-skyblue-50 dark:bg-skyblue-900/30 text-skyblue-600 dark:text-skyblue-400 rounded-full text-[9px] font-black uppercase mb-6 tracking-[0.3em] border border-skyblue-100/50">Enterprise Vault</span>
                <h1 className="text-5xl sm:text-6xl font-black text-slate-900 dark:text-white leading-[1.1] mb-8 tracking-tighter">
                  Secure Digital <br/> <span className="text-skyblue-500">Assets</span>
                </h1>
                <p className="text-base text-slate-500 dark:text-slate-400 mb-10 leading-relaxed font-medium">
                  Verified high-performance tools for networking and security professionals.
                </p>
                <div className="flex flex-col sm:flex-row items-center justify-center gap-4">
                  <button onClick={() => setCurrentView('category')} className="w-full sm:w-auto bg-skyblue-500 hover:bg-skyblue-600 text-white font-black px-10 py-4 rounded-2xl shadow-xl shadow-skyblue-500/20 transition-all active:scale-95 text-sm uppercase tracking-widest">
                    Explore Marketplace
                  </button>
                </div>
              </div>
            </section>

            {/* List items by Category Headers as in the reference image */}
            {settings.categories.map(category => {
              const categoryProducts = products.filter(p => p.isVisible && p.category === category.id);
              return renderProductList(categoryProducts, category.name);
            })}
          </div>
        )}

        {currentView === 'category' && (
          <div className="py-8">
             <div className="flex flex-col md:flex-row items-start md:items-center justify-between mb-10 gap-6">
                <div>
                   <h2 className="text-3xl font-black dark:text-white tracking-tighter uppercase">Market <span className="text-skyblue-500">Archive</span></h2>
                   <p className="text-slate-400 text-sm font-bold mt-1">Filtering by: {selectedCategory ? settings.categories.find(c => c.id === selectedCategory)?.name : 'All Segments'}</p>
                </div>
                <div className="flex flex-wrap gap-2">
                   <button onClick={() => setSelectedCategory(null)} className={`px-5 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${!selectedCategory ? 'bg-skyblue-500 text-white' : 'bg-white dark:bg-slate-900 text-slate-400 border border-slate-100'}`}>All</button>
                   {settings.categories.map(c => (
                     <button key={c.id} onClick={() => setSelectedCategory(c.id)} className={`px-5 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${selectedCategory === c.id ? 'bg-skyblue-500 text-white' : 'bg-white dark:bg-slate-900 text-slate-400 border border-slate-100'}`}>{c.name}</button>
                   ))}
