      <main className="flex-1 max-w-5xl mx-auto px-4 sm:px-6 lg:px-8 w-full py-8">
        {currentView === 'home' && (
          <div className="space-y-12">
            <section className="relative px-6 py-20 bg-gradient-to-br from-white to-slate-50 dark:from-slate-900 dark:to-slate-950 rounded-[3rem] border border-slate-100 dark:border-slate-800 overflow-hidden shadow-2xl">
