            <div className="bg-white dark:bg-slate-900 rounded-[2.5rem] p-8 border border-slate-100 dark:border-slate-800 flex flex-col md:flex-row gap-12 shadow-xl">
              <div className="flex-1 bg-slate-50 dark:bg-slate-950 rounded-3xl flex items-center justify-center p-8 aspect-square">
                <img src={selectedProduct.image} className="max-w-full max-h-full object-contain" alt={selectedProduct.name} />
              </div>
              <div className="flex-1 flex flex-col justify-center space-y-6">
                <span className="text-skyblue-500 font-black uppercase text-[10px] tracking-widest">{selectedProduct.category}</span>
                <h1 className="text-4xl font-black dark:text-white tracking-tighter uppercase">{selectedProduct.name}</h1>
                <div className="flex items-center space-x-4">
                  <p className="text-4xl font-black text-skyblue-600 dark:text-skyblue-400">₦{selectedProduct.price.toLocaleString()}</p>
                </div>
                <p className="text-sm text-slate-500 dark:text-slate-400 leading-relaxed font-medium">
                  {selectedProduct.description}
                </p>
                <div className="grid grid-cols-2 gap-3">
                  {selectedProduct.features.map((f, i) => (
                    <div key={i} className="flex items-center space-x-2 text-slate-600 dark:text-slate-400">
                      <i className="fa-solid fa-circle-check text-skyblue-400 text-[10px]"></i>
                      <span className="text-xs font-bold">{f}</span>
                    </div>
                  ))}
                </div>
                <button onClick={() => addToCart(selectedProduct)} className="w-full bg-skyblue-500 hover:bg-skyblue-600 text-white font-black py-4 rounded-2xl shadow-xl transition-all active:scale-95 mt-6 text-sm uppercase tracking-widest">
                  Secure Purchase
                </button>
              </div>
            </div>
          </div>
        )}

        {currentView === 'profile' && (
          currentUser ? (
            <UserProfile user={currentUser} settings={settings} onFundWallet={() => setCurrentView('fund_wallet')} onLogout={() => { setCurrentUser(null); localStorage.removeItem('nettoolz_logged_user_email'); setCurrentView('home'); }} />
          ) : (
            <UserAuth users={users} onAuth={handleAuth} onCancel={() => setCurrentView('home')} />
          )
        )}

        {currentView === 'fund_wallet' && <WalletFunding settings={settings} onBack={() => setCurrentView('profile')} onFundSuccess={handleFundSuccess} />}
        {currentView === 'admin_dashboard' && isAdminLoggedIn && <AdminDashboard products={products} settings={settings} admins={admins} onUpdateProducts={handleUpdateProducts} onUpdateSettings={handleUpdateSettings} onUpdateAdmins={handleUpdateAdmins} onLogout={() => { setIsAdminLoggedIn(false); localStorage.removeItem('nettoolz_admin_logged'); setCurrentView('home'); }} />}
        {currentView === 'admin_login' && <AdminLogin onLogin={(s) => { if(s) { setIsAdminLoggedIn(true); localStorage.setItem('nettoolz_admin_logged', 'true'); setCurrentView('admin_dashboard'); } }} onCancel={() => setCurrentView('home')} />}
      </main>

      {isCartOpen && (
        <div className="fixed inset-0 z-[110] flex justify-end">
          <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm" onClick={() => setIsCartOpen(false)}></div>
          <div className="relative w-full max-w-sm bg-white dark:bg-slate-900 h-full p-8 flex flex-col shadow-2xl animate-in slide-in-from-right duration-300">
            <div className="flex items-center justify-between mb-8">
              <h2 className="text-3xl font-black dark:text-white tracking-tighter uppercase">Cart</h2>
              <button onClick={() => setIsCartOpen(false)} className="text-slate-400 hover:text-slate-900"><i className="fa-solid fa-xmark text-xl"></i></button>
            </div>

            <div className="flex-1 overflow-y-auto space-y-4 custom-scrollbar pr-2">
              {cart.map(item => (
                <div key={item.id} className="flex gap-4 p-4 bg-slate-50 dark:bg-slate-800 rounded-2xl border border-slate-100 dark:border-slate-700">
                  <div className="w-16 h-16 bg-white dark:bg-slate-900 rounded-xl flex items-center justify-center p-2">
                    <img src={item.image} className="w-full h-full object-contain" alt={item.name} />
                  </div>
                  <div className="flex-1">
                    <p className="font-black dark:text-white text-sm leading-tight mb-1 uppercase">{item.name}</p>
                    <div className="flex items-center justify-between">
                      <p className="text-skyblue-600 dark:text-skyblue-400 font-black text-xs">₦{item.price.toLocaleString()}</p>
                      <span className="text-[10px] font-black text-slate-400 uppercase">Qty: {item.quantity}</span>
                    </div>
                  </div>
                  <button onClick={() => setCart(cart.filter(i => i.id !== item.id))} className="text-slate-300 hover:text-red-500 transition-colors"><i className="fa-solid fa-trash-can text-sm"></i></button>
                </div>
              ))}
              {cart.length === 0 && (
                <div className="text-center py-20 opacity-30">
                  <i className="fa-solid fa-shopping-basket text-5xl mb-4"></i>
                  <p className="text-xs font-black uppercase tracking-widest">Your cart is empty</p>
                </div>
              )}
            </div>

            {cart.length > 0 && (
              <div className="pt-6 border-t dark:border-slate-800 mt-auto">
                <div className="flex justify-between text-2xl font-black mb-8 dark:text-white tracking-tighter uppercase">
                  <span>Total</span>
                  <span className="text-skyblue-500">₦{cart.reduce((a, i) => a + (i.price * i.quantity), 0).toLocaleString()}</span>
                </div>
                <button onClick={handleCheckout} disabled={isProcessingCheckout} className="w-full bg-skyblue-500 text-white font-black py-4 rounded-xl shadow-lg hover:bg-skyblue-600 transition-all active:scale-95 disabled:bg-slate-300 text-xs uppercase tracking-widest">
                  {isProcessingCheckout ? "Processing..." : "Confirm Checkout"}
                </button>
              </div>
            )}
          </div>
        </div>
      )}

      <footer className="bg-white dark:bg-slate-950 border-t border-slate-100 dark:border-slate-900 py-12 text-center mt-auto">
        <div className="max-w-7xl mx-auto px-4">
          <div className="flex flex-col items-center mb-6">
             <div className="mb-4">
                <LogoIcon />
             </div>
            <div className="text-2xl font-black tracking-tighter text-slate-900 dark:text-white">
              NET<span className="text-skyblue-500">TOOLZ</span>
            </div>
          </div>
          <p className="text-slate-400 text-[9px] font-black uppercase tracking-[0.3em]">© 2024 NETTOOLZ Enterprise • Premium Network Assets</p>
          <button onClick={() => setCurrentView('admin_login')} className="mt-4 text-[9px] text-slate-300 hover:text-skyblue-500 font-black tracking-widest transition-colors opacity-30">SYSTEM ACCESS</button>
        </div>
      </footer>
      <GeminiAssistant />
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Product, CartItem, ViewState, SiteSettings, AdminUser, User, UserOrder } from './types';
import { INITIAL_PRODUCTS, CATEGORIES } from './constants';
import { dbService } from './services/dbService';
import { generateProductImage } from './services/geminiService';
import Navbar, { LogoIcon } from './components/Navbar';
import ProductCard from './components/ProductCard';
import AdminLogin from './components/AdminLogin';
import AdminDashboard from './components/AdminDashboard';
import UserAuth from './components/UserAuth';
import UserProfile from './components/UserProfile';
import WalletFunding from './components/WalletFunding';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<ViewState>('home');
  const [selectedCategory, setSelectedCategory] = useState<string | null>(null);
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [isProcessingCheckout, setIsProcessingCheckout] = useState(false);
  const [isLoadingDB, setIsLoadingDB] = useState(true);
  const [isGeneratingImages, setIsGeneratingImages] = useState(false);
  const generationInProgressRef = useRef(false);

  const [products, setProducts] = useState<Product[]>([]);
  const [admins, setAdmins] = useState<AdminUser[]>([{ id: '1', username: 'Admin', role: 'super' }]);
  const [settings, setSettings] = useState<SiteSettings>({
    currency: 'NGN',
    currencySymbol: '₦',
    storeName: 'NETTOOLZ',
    usdtToNairaRate: 1650, 
    geminiApiKey: '',
    categories: CATEGORIES,
    paymentMethods: [
      { 
        id: 'bank1', 
        type: 'bank', 
        name: 'KoralPay (Automated Bank)', 
        details: 'Transfer to the virtual account generated at checkout.', 
        isActive: true,
        isAutomated: true,
        apiPublicKey: 'pk_live_nettoolz_7721',
        merchantId: 'MER-88122'
      },
      { 
        id: 'crypto1', 
        type: 'crypto', 
        name: 'Crypto (Instant Credit)', 
        details: 'Payment credits after 1 network confirmation.', 
        walletAddress: 'TYxxxxxxxxxxxxxxxxxxxxxx',
        network: 'TRC20',
        isActive: true,
        isAutomated: true,
        apiPublicKey: 'pk_live_crypto_9921',
        merchantId: 'MER-99123'
      }
    ]
  });
  const [isAdminLoggedIn, setIsAdminLoggedIn] = useState(false);
  const [users, setUsers] = useState<User[]>([]);
  const [currentUser, setCurrentUser] = useState<User | null>(null);

  const autoGenerateMissingImages = useCallback(async (currentProducts: Product[]) => {
    if (generationInProgressRef.current) return;

    const productsToUpdate = currentProducts.filter(p => p.image.includes('picsum.photos'));
    if (productsToUpdate.length === 0) return;

    generationInProgressRef.current = true;
    setIsGeneratingImages(true);

    const updatedProducts = [...currentProducts];

    for (let i = 0; i < productsToUpdate.length; i++) {
      const p = productsToUpdate[i];
      const newImage = await generateProductImage(p);
      if (newImage) {
        const index = updatedProducts.findIndex(item => item.id === p.id);
        if (index !== -1) {
          updatedProducts[index] = { ...updatedProducts[index], image: newImage };
        }
      }
      await new Promise(resolve => setTimeout(resolve, 1500));
    }

    setProducts(updatedProducts);
    await dbService.saveProducts(updatedProducts);
    setIsGeneratingImages(false);
    generationInProgressRef.current = false;
  }, []);

  useEffect(() => {
    const initApp = async () => {
      try {
        await dbService.init();

        const savedSettings = await dbService.getSettings();
        if (savedSettings) setSettings(savedSettings);
        else await dbService.saveSettings(settings);

        const savedProducts = await dbService.getAllProducts();
        let currentProductsList = [];
        if (savedProducts && savedProducts.length > 0) {
          currentProductsList = savedProducts;
        } else {
          await dbService.saveProducts(INITIAL_PRODUCTS);
          currentProductsList = INITIAL_PRODUCTS;
        }
        setProducts(currentProductsList);

        const savedAdmins = await dbService.getAllAdmins();
        if (savedAdmins && savedAdmins.length > 0) setAdmins(savedAdmins);
        else await dbService.saveAdmins(admins);

        const savedUsers = await dbService.getAllUsers();
        setUsers(savedUsers);

        const savedAdmin = localStorage.getItem('nettoolz_admin_logged');
        if (savedAdmin === 'true') setIsAdminLoggedIn(true);

        const loggedUserEmail = localStorage.getItem('nettoolz_logged_user_email');
        if (loggedUserEmail) {
          const found = savedUsers.find(u => u.email === loggedUserEmail);
          if (found) setCurrentUser(found);
        }

        autoGenerateMissingImages(currentProductsList);

      } catch (err) {
        console.error("Database initialization failed:", err);
      } finally {
        setIsLoadingDB(false);
      }
    };

    initApp();
  }, [autoGenerateMissingImages]);

  const handleUpdateProducts = async (newProducts: Product[]) => {
    setProducts(newProducts);
    await dbService.saveProducts(newProducts);
  };

  const handleUpdateSettings = async (newSettings: SiteSettings) => {
    setSettings(newSettings);
    await dbService.saveSettings(newSettings);
  };

  const handleUpdateAdmins = async (newAdmins: AdminUser[]) => {
    setAdmins(newAdmins);
    await dbService.saveAdmins(newAdmins);
  };

  const handleAuth = async (user: User) => {
    const exists = users.find(u => u.email === user.email);
    const updatedUsers = exists 
      ? users.map(u => u.email === user.email ? user : u) 
      : [...users, user];

    setUsers(updatedUsers);
    setCurrentUser(user);
    await dbService.saveUser(user);
    localStorage.setItem('nettoolz_logged_user_email', user.email);
    setCurrentView('profile');
  };

  const handleFundSuccess = async (amount: number) => {
    if (!currentUser) return;
    const updatedUser = {
      ...currentUser,
      balance: currentUser.balance + amount
    };
    setUsers(prev => prev.map(u => u.email === updatedUser.email ? updatedUser : u));
    setCurrentUser(updatedUser);
    await dbService.saveUser(updatedUser);
  };

  const addToCart = (product: Product) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) return prev.map(item => item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item);
      return [...prev, { ...product, quantity: 1 }];
    });
    setIsCartOpen(true);
  };

  const handleCheckout = async () => {
    if (!currentUser) { setCurrentView('profile'); setIsCartOpen(false); return; }
    const total = cart.reduce((acc, item) => acc + (item.price * item.quantity), 0);
    if (currentUser.balance < total) { alert('Insufficient balance.'); setCurrentView('fund_wallet'); setIsCartOpen(false); return; }

    setIsProcessingCheckout(true);
    await new Promise(resolve => setTimeout(resolve, 1500));
    const newOrders: UserOrder[] = cart.map(item => ({ id: Date.now().toString() + Math.random(), productId: item.id, productName: item.name, content: item.secretContent || 'Processing...', price: item.price, timestamp: Date.now() }));
    const updatedUser = { ...currentUser, balance: currentUser.balance - total, orders: [...currentUser.orders, ...newOrders] };

    setUsers(prev => prev.map(u => u.email === updatedUser.email ? updatedUser : u));
    setCurrentUser(updatedUser);
    await dbService.saveUser(updatedUser);

    setCart([]); 
    setIsCartOpen(false); 
    setIsProcessingCheckout(false); 
    setCurrentView('profile');
    alert('Purchase confirmed!');
  };

  const renderProductList = (categoryItems: Product[], categoryName: string) => {
    if (categoryItems.length === 0) return null;
    return (
      <div className="mb-12">
        <div className="bg-gradient-to-r from-skyblue-700 via-skyblue-500 to-skyblue-800 rounded-t-[2rem] p-6 flex items-center justify-between text-white shadow-xl">
          <div className="flex items-center space-x-3">
            <h2 className="text-sm sm:text-lg font-black uppercase tracking-widest">{categoryName.replace("&#039;", "'")}</h2>
            <div className="bg-white/20 px-3 py-1 rounded-full text-xs font-black min-w-[32px] text-center">
              {categoryItems.length}
            </div>
          </div>
          <div className="flex items-center space-x-2">
            <button className="w-10 h-10 bg-white/10 hover:bg-white/20 rounded-xl flex items-center justify-center transition-colors">
              <i className="fa-solid fa-chevron-down text-sm"></i>
            </button>
            <button 
              onClick={() => { setSelectedCategory(categoryItems[0].category); setCurrentView('category'); }}
              className="bg-white/10 hover:bg-white/20 px-4 py-2 rounded-xl text-xs font-black uppercase flex items-center space-x-2 transition-colors"
            >
              <span>View All</span>
              <i className="fa-solid fa-arrow-right"></i>
            </button>
          </div>
        </div>

        <div className="bg-white dark:bg-slate-900/50 border-x border-b border-slate-100 dark:border-slate-800 rounded-b-[2rem] p-6 space-y-2 shadow-sm">
          {categoryItems.map(p => (
            <ProductCard 
              key={p.id} 
              product={p} 
              onAddToCart={addToCart} 
              onViewDetails={(p) => { setSelectedProduct(p); setCurrentView('product'); }} 
            />
          ))}
        </div>
      </div>
    );
  };

  if (isLoadingDB) {
    return (
      <div className="h-screen w-screen flex flex-col items-center justify-center bg-white dark:bg-slate-950">
        <div className="relative w-24 h-24 mb-6">
          <div className="absolute inset-0 border-4 border-skyblue-100 dark:border-slate-800 rounded-full"></div>
          <div className="absolute inset-0 border-4 border-skyblue-50 rounded-full border-t-transparent animate-spin"></div>
        </div>
        <h1 className="text-xl font-black text-slate-800 dark:text-white uppercase tracking-widest">NETTOOLZ Portal</h1>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex flex-col bg-slate-50 dark:bg-slate-950 transition-colors">
      <Navbar 
        cartCount={cart.reduce((acc, item) => acc + item.quantity, 0)} 
        isDarkMode={isDarkMode} 
        logoUrl={settings.logoUrl}
        currentUserEmail={currentUser?.email}
        onNavigate={setCurrentView} 
        onOpenCart={() => setIsCartOpen(true)} 
        onToggleTheme={() => { setIsDarkMode(!isDarkMode); document.documentElement.classList.toggle('dark'); }} 
      />

      {isGeneratingImages && (
        <div className="bg-skyblue-500 text-white text-[10px] font-black uppercase tracking-[0.2em] py-2 text-center animate-pulse sticky top-20 z-[45]">
          AI Assistant is generating high-quality product renders... Sequential Processing Active
        </div>
      )}

      <main className="flex-1 max-w-5xl mx-auto px-4 sm:px-6 lg:px-8 w-full py-8">
        {currentView === 'home' && (
          <div className="space-y-12">
            <section className="relative px-6 py-20 bg-gradient-to-br from-white to-slate-50 dark:from-slate-900 dark:to-slate-950 rounded-[3rem] border border-slate-100 dark:border-slate-800 overflow-hidden shadow-2xl">
              <div className="relative z-10 text-center max-w-3xl mx-auto">
                <span className="inline-block px-4 py-1.5 bg-skyblue-50 dark:bg-skyblue-900/30 text-skyblue-600 dark:text-skyblue-400 rounded-full text-[9px] font-black uppercase mb-6 tracking-[0.3em] border border-skyblue-100/50">Enterprise Vault</span>
                <h1 className="text-5xl sm:text-6xl font-black text-slate-900 dark:text-white leading-[1.1] mb-8 tracking-tighter uppercase">
                  Secure <span className="text-skyblue-500">Networking</span> Tools
                </h1>
                <p className="text-base text-slate-500 dark:text-slate-400 mb-10 leading-relaxed font-medium">
                  Verified high-performance assets for security professionals.
                </p>
                <div className="flex flex-col sm:flex-row items-center justify-center gap-4">
                  <button onClick={() => setCurrentView('category')} className="w-full sm:w-auto bg-skyblue-500 hover:bg-skyblue-600 text-white font-black px-10 py-4 rounded-2xl shadow-xl shadow-skyblue-500/20 transition-all active:scale-95 text-sm uppercase tracking-widest">
                    Explore Marketplace
                  </button>
                </div>
              </div>
            </section>

            {settings.categories.map(category => {
              const categoryProducts = products.filter(p => p.isVisible && p.category === category.id);
              return renderProductList(categoryProducts, category.name);
            })}
          </div>
        )}

        {currentView === 'category' && (
          <div className="py-8">
             <div className="flex flex-col md:flex-row items-start md:items-center justify-between mb-10 gap-6">
                <div>
                   <h2 className="text-3xl font-black dark:text-white tracking-tighter uppercase">Market <span className="text-skyblue-500">Archive</span></h2>
                   <p className="text-slate-400 text-sm font-bold mt-1">Filtering by: {selectedCategory ? settings.categories.find(c => c.id === selectedCategory)?.name : 'All Segments'}</p>
                </div>
                <div className="flex flex-wrap gap-2">
                   <button onClick={() => setSelectedCategory(null)} className={`px-5 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${!selectedCategory ? 'bg-skyblue-500 text-white' : 'bg-white dark:bg-slate-900 text-slate-400 border border-slate-100'}`}>All</button>
                   {settings.categories.map(c => (
                     <button key={c.id} onClick={() => setSelectedCategory(c.id)} className={`px-5 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${selectedCategory === c.id ? 'bg-skyblue-500 text-white' : 'bg-white dark:bg-slate-900 text-slate-400 border border-slate-100'}`}>{c.name}</button>
                   ))}
                </div>
             </div>

             <div className="space-y-4">
                {products.filter(p => p.isVisible && (!selectedCategory || p.category === selectedCategory)).map(p => (
                  <ProductCard key={p.id} product={p} onAddToCart={addToCart} onViewDetails={(p) => { setSelectedProduct(p); setCurrentView('product'); }} />
                ))}
             </div>
          </div>
        )}

        {currentView === 'product' && selectedProduct && (
          <div className="py-8">
            <button onClick={() => setCurrentView('category')} className="mb-8 text-slate-400 font-bold hover:text-skyblue-500 flex items-center transition-colors">
              <i className="fa-solid fa-arrow-left-long mr-2"></i> Back
            </button>
            <div className="bg-white dark:bg-slate-900 rounded-[2.5rem] p-8 border border-slate-100 dark:border-slate-800 flex flex-col md:flex-row gap-12 shadow-xl">
              <div className="flex-1 bg-slate-50 dark:bg-slate-950 rounded-3xl flex items-center justify-center p-8 aspect-square">
                <img src={selectedProduct.image} className="max-w-full max-h-full object-contain" alt={selectedProduct.name} />
              </div>
              <div className="flex-1 flex flex-col justify-center space-y-6">
                <span className="text-skyblue-500 font-black uppercase text-[10px] tracking-widest">{selectedProduct.category}</span>
                <h1 className="text-4xl font-black dark:text-white tracking-tighter uppercase">{selectedProduct.name}</h1>
                <div className="flex items-center space-x-4">
                  <p className="text-4xl font-black text-skyblue-600 dark:text-skyblue-400">₦{selectedProduct.price.toLocaleString()}</p>
                </div>
                <p className="text-sm text-slate-500 dark:text-slate-400 leading-relaxed font-medium">
                  {selectedProduct.description}
                </p>
                <div className="grid grid-cols-2 gap-3">
                  {selectedProduct.features.map((f, i) => (
                    <div key={i} className="flex items-center space-x-2 text-slate-600 dark:text-slate-400">
                      <i className="fa-solid fa-circle-check text-skyblue-400 text-[10px]"></i>
                      <span className="text-xs font-bold">{f}</span>
                    </div>
                  ))}
                </div>
                <button onClick={() => addToCart(selectedProduct)} className="w-full bg-skyblue-500 hover:bg-skyblue-600 text-white font-black py-4 rounded-2xl shadow-xl transition-all active:scale-95 mt-6 text-sm uppercase tracking-widest">
                  Secure Purchase
                </button>
              </div>
            </div>
          </div>
        )}

        {currentView === 'profile' && (
          currentUser ? (
            <UserProfile user={currentUser} settings={settings} onFundWallet={() => setCurrentView('fund_wallet')} onLogout={() => { setCurrentUser(null); localStorage.removeItem('nettoolz_logged_user_email'); setCurrentView('home'); }} />
          ) : (
            <UserAuth users={users} onAuth={handleAuth} onCancel={() => setCurrentView('home')} />
          )
        )}

        {currentView === 'fund_wallet' && <WalletFunding settings={settings} onBack={() => setCurrentView('profile')} onFundSuccess={handleFundSuccess} />}
        {currentView === 'admin_dashboard' && isAdminLoggedIn && <AdminDashboard products={products} settings={settings} admins={admins} onUpdateProducts={handleUpdateProducts} onUpdateSettings={handleUpdateSettings} onUpdateAdmins={handleUpdateAdmins} onLogout={() => { setIsAdminLoggedIn(false); localStorage.removeItem('nettoolz_admin_logged'); setCurrentView('home'); }} />}
        {currentView === 'admin_login' && <AdminLogin onLogin={(s) => { if(s) { setIsAdminLoggedIn(true); localStorage.setItem('nettoolz_admin_logged', 'true'); setCurrentView('admin_dashboard'); } }} onCancel={() => setCurrentView('home')} />}
      </main>

      {isCartOpen && (
        <div className="fixed inset-0 z-[110] flex justify-end">
          <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm" onClick={() => setIsCartOpen(false)}></div>
          <div className="relative w-full max-sm bg-white dark:bg-slate-900 h-full p-8 flex flex-col shadow-2xl animate-in slide-in-from-right duration-300">
            <div className="flex items-center justify-between mb-8">
              <h2 className="text-3xl font-black dark:text-white tracking-tighter uppercase">Cart</h2>
              <button onClick={() => setIsCartOpen(false)} className="text-slate-400 hover:text-slate-900"><i className="fa-solid fa-xmark text-xl"></i></button>
            </div>

            <div className="flex-1 overflow-y-auto space-y-4 custom-scrollbar pr-2">
              {cart.map(item => (
                <div key={item.id} className="flex gap-4 p-4 bg-slate-50 dark:bg-slate-800 rounded-2xl border border-slate-100 dark:border-slate-700">
                  <div className="w-16 h-16 bg-white dark:bg-slate-900 rounded-xl flex items-center justify-center p-2">
                    <img src={item.image} className="w-full h-full object-contain" alt={item.name} />
                  </div>
                  <div className="flex-1">
                    <p className="font-black dark:text-white text-sm leading-tight mb-1 uppercase">{item.name}</p>
                    <div className="flex items-center justify-between">
                      <p className="text-skyblue-600 dark:text-skyblue-400 font-black text-xs">₦{item.price.toLocaleString()}</p>
                      <span className="text-[10px] font-black text-slate-400 uppercase">Qty: {item.quantity}</span>
                    </div>
                  </div>
                  <button onClick={() => setCart(cart.filter(i => i.id !== item.id))} className="text-slate-300 hover:text-red-500 transition-colors"><i className="fa-solid fa-trash-can text-sm"></i></button>
                </div>
              ))}
              {cart.length === 0 && (
                <div className="text-center py-20 opacity-30">
                  <i className="fa-solid fa-shopping-basket text-5xl mb-4"></i>
                  <p className="text-xs font-black uppercase tracking-widest">Your cart is empty</p>
                </div>
              )}
            </div>

            {cart.length > 0 && (
              <div className="pt-6 border-t dark:border-slate-800 mt-auto">
                <div className="flex justify-between text-2xl font-black mb-8 dark:text-white tracking-tighter uppercase">
                  <span>Total</span>
                  <span className="text-skyblue-500">₦{cart.reduce((a, i) => a + (i.price * i.quantity), 0).toLocaleString()}</span>
                </div>
                <button onClick={handleCheckout} disabled={isProcessingCheckout} className="w-full bg-skyblue-500 text-white font-black py-4 rounded-xl shadow-lg hover:bg-skyblue-600 transition-all active:scale-95 disabled:bg-slate-300 text-xs uppercase tracking-widest">
                  {isProcessingCheckout ? "Processing..." : "Confirm Checkout"}
                </button>
              </div>
            )}
          </div>
        </div>
      )}

      <footer className="bg-white dark:bg-slate-950 border-t border-slate-100 dark:border-slate-900 py-12 text-center mt-auto">
        <div className="max-w-7xl mx-auto px-4">
          <div className="flex flex-col items-center mb-6">
             <div className="mb-4">
                <LogoIcon />
             </div>
            <div className="text-2xl font-black tracking-tighter text-slate-900 dark:text-white">
              NET<span className="text-skyblue-500">TOOLZ</span>
            </div>
          </div>
          <p className="text-slate-400 text-[9px] font-black uppercase tracking-[0.3em]">© 2024 NETTOOLZ Enterprise • Premium Network Assets</p>
          <button onClick={() => setCurrentView('admin_login')} className="mt-4 text-[9px] text-slate-300 hover:text-skyblue-500 font-black tracking-widest transition-colors opacity-30">SYSTEM ACCESS</button>
        </div>
      </footer>
    </div>
  );
};

export default App;

export interface Product {
  id: string;
  name: string;
  description: string;
  price: number;
  category: string;
  stock: number;
  rating: number;
  image: string;
  features: string[];
  isVisible: boolean;
  secretContent: string;
}

export interface CartItem extends Product {
  quantity: number;
}

export interface Category {
  id: string;
  name: string;
  icon: string;
}

export interface PaymentMethod {
  id: string;
  type: 'bank' | 'crypto';
  name: string;
  details: string;
  isActive: boolean;
  bankName?: string;
  accountNumber?: string;
  accountName?: string;
  walletAddress?: string;
  network?: string;
  // API Configuration
  isAutomated: boolean;
  apiPublicKey?: string;
  apiSecretKey?: string;
  merchantId?: string;
  webhookUrl?: string;
}

export interface SiteSettings {
  currency: string;
  currencySymbol: string;
  storeName: string;
  logoUrl?: string;
  paymentMethods: PaymentMethod[];
  usdtToNairaRate: number;
  categories: Category[];
}

export interface UserOrder {
  id: string;
  productId: string;
  productName: string;
  content: string;
  price: number;
  timestamp: number;
}

export interface User {
  id: string;
  email: string;
  password: string;
  balance: number;
  orders: UserOrder[];
}

export interface AdminUser {
  id: string;
  username: string;
  role: 'super' | 'editor';
}

export type ViewState = 'home' | 'category' | 'product' | 'cart' | 'profile' | 'admin_login' | 'admin_dashboard' | 'user_auth' | 'fund_wallet';

import React, { useState, useEffect } from 'react';
import { Product, CartItem, ViewState, SiteSettings, AdminUser, User, UserOrder } from './types';
import { INITIAL_PRODUCTS, CATEGORIES } from './constants';
import { dbService } from './services/dbService';
import Navbar, { LogoIcon } from './components/Navbar';
import ProductCard from './components/ProductCard';
import AdminLogin from './components/AdminLogin';
import AdminDashboard from './components/AdminDashboard';
import UserAuth from './components/UserAuth';
import UserProfile from './components/UserProfile';
import WalletFunding from './components/WalletFunding';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<ViewState>('home');
  const [selectedCategory, setSelectedCategory] = useState<string | null>(null);
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [isProcessingCheckout, setIsProcessingCheckout] = useState(false);
  const [isLoadingDB, setIsLoadingDB] = useState(true);

  const [products, setProducts] = useState<Product[]>([]);
  const [admins, setAdmins] = useState<AdminUser[]>([{ id: '1', username: 'Admin', role: 'super' }]);
  const [settings, setSettings] = useState<SiteSettings>({
    currency: 'NGN',
    currencySymbol: '₦',
    storeName: 'NETTOOLZ',
    usdtToNairaRate: 1650, 
    categories: CATEGORIES,
    paymentMethods: [
      { 
        id: 'bank1', 
        type: 'bank', 
        name: 'KoralPay (Automated Bank)', 
        details: 'Transfer to the virtual account generated at checkout.', 
        isActive: true,
        isAutomated: true,
        apiPublicKey: 'pk_live_nettoolz_7721',
        merchantId: 'MER-88122'
      },
      { 
        id: 'crypto1', 
        type: 'crypto', 
        name: 'Crypto (Instant Credit)', 
        details: 'Payment credits after 1 network confirmation.', 
        walletAddress: 'TYxxxxxxxxxxxxxxxxxxxxxx',
        network: 'TRC20',
        isActive: true,
        isAutomated: true,
        apiPublicKey: 'pk_live_crypto_9921',
        merchantId: 'MER-99123'
      }
    ]
  });
  const [isAdminLoggedIn, setIsAdminLoggedIn] = useState(false);
  const [users, setUsers] = useState<User[]>([]);
  const [currentUser, setCurrentUser] = useState<User | null>(null);

  useEffect(() => {
    const initApp = async () => {
      try {
        await dbService.init();

        const savedSettings = await dbService.getSettings();
        if (savedSettings) setSettings(savedSettings);
        else await dbService.saveSettings(settings);

        const savedProducts = await dbService.getAllProducts();
        let currentProductsList = [];
        if (savedProducts && savedProducts.length > 0) {
          currentProductsList = savedProducts;
        } else {
          await dbService.saveProducts(INITIAL_PRODUCTS);
          currentProductsList = INITIAL_PRODUCTS;
        }
        setProducts(currentProductsList);

        const savedAdmins = await dbService.getAllAdmins();
        if (savedAdmins && savedAdmins.length > 0) setAdmins(savedAdmins);
        else await dbService.saveAdmins(admins);

        const savedUsers = await dbService.getAllUsers();
        setUsers(savedUsers);

        const savedAdmin = localStorage.getItem('nettoolz_admin_logged');
        if (savedAdmin === 'true') setIsAdminLoggedIn(true);

        const loggedUserEmail = localStorage.getItem('nettoolz_logged_user_email');
        if (loggedUserEmail) {
          const found = savedUsers.find(u => u.email === loggedUserEmail);
          if (found) setCurrentUser(found);
        }

      } catch (err) {
        console.error("Database initialization failed:", err);
      } finally {
        setIsLoadingDB(false);
      }
    };

    initApp();
  }, []);

  const handleUpdateProducts = async (newProducts: Product[]) => {
    setProducts(newProducts);
    await dbService.saveProducts(newProducts);
  };

  const handleUpdateSettings = async (newSettings: SiteSettings) => {
    setSettings(newSettings);
    await dbService.saveSettings(newSettings);
  };

  const handleUpdateAdmins = async (newAdmins: AdminUser[]) => {
    setAdmins(newAdmins);
    await dbService.saveAdmins(newAdmins);
  };

  const handleAuth = async (user: User) => {
    const exists = users.find(u => u.email === user.email);
    const updatedUsers = exists 
      ? users.map(u => u.email === user.email ? user : u) 
      : [...users, user];

    setUsers(updatedUsers);
    setCurrentUser(user);
    await dbService.saveUser(user);
    localStorage.setItem('nettoolz_logged_user_email', user.email);
    setCurrentView('profile');
  };

  const handleFundSuccess = async (amount: number) => {
    if (!currentUser) return;
    const updatedUser = {
      ...currentUser,
      balance: currentUser.balance + amount
    };
    setUsers(prev => prev.map(u => u.email === updatedUser.email ? updatedUser : u));
    setCurrentUser(updatedUser);
    await dbService.saveUser(updatedUser);
  };

  const addToCart = (product: Product) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) return prev.map(item => item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item);
      return [...prev, { ...product, quantity: 1 }];
    });
    setIsCartOpen(true);
  };

  const handleCheckout = async () => {
    if (!currentUser) { setCurrentView('profile'); setIsCartOpen(false); return; }
    const total = cart.reduce((acc, item) => acc + (item.price * item.quantity), 0);
    if (currentUser.balance < total) { alert('Insufficient balance.'); setCurrentView('fund_wallet'); setIsCartOpen(false); return; }

    setIsProcessingCheckout(true);
    await new Promise(resolve => setTimeout(resolve, 1500));
    const newOrders: UserOrder[] = cart.map(item => ({ id: Date.now().toString() + Math.random(), productId: item.id, productName: item.name, content: item.secretContent || 'Processing...', price: item.price, timestamp: Date.now() }));
    const updatedUser = { ...currentUser, balance: currentUser.balance - total, orders: [...currentUser.orders, ...newOrders] };

    setUsers(prev => prev.map(u => u.email === updatedUser.email ? updatedUser : u));
    setCurrentUser(updatedUser);
    await dbService.saveUser(updatedUser);

    setCart([]); 
    setIsCartOpen(false); 
    setIsProcessingCheckout(false); 
    setCurrentView('profile');
    alert('Purchase confirmed!');
  };

  const renderProductList = (categoryItems: Product[], categoryName: string) => {
    if (categoryItems.length === 0) return null;
    return (
      <div className="mb-12">
        <div className="bg-gradient-to-r from-skyblue-700 via-skyblue-500 to-skyblue-800 rounded-t-[2rem] p-6 flex items-center justify-between text-white shadow-xl">
          <div className="flex items-center space-x-3">
            <h2 className="text-sm sm:text-lg font-black uppercase tracking-widest">{categoryName.replace("&#039;", "'")}</h2>
            <div className="bg-white/20 px-3 py-1 rounded-full text-xs font-black min-w-[32px] text-center">
              {categoryItems.length}
            </div>
          </div>
          <div className="flex items-center space-x-2">
            <button className="w-10 h-10 bg-white/10 hover:bg-white/20 rounded-xl flex items-center justify-center transition-colors">
              <i className="fa-solid fa-chevron-down text-sm"></i>
            </button>
            <button 
              onClick={() => { setSelectedCategory(categoryItems[0].category); setCurrentView('category'); }}
              className="bg-white/10 hover:bg-white/20 px-4 py-2 rounded-xl text-xs font-black uppercase flex items-center space-x-2 transition-colors"
            >
              <span>View All</span>
              <i className="fa-solid fa-arrow-right"></i>
            </button>
          </div>
        </div>

        <div className="bg-white dark:bg-slate-900/50 border-x border-b border-slate-100 dark:border-slate-800 rounded-b-[2rem] p-6 space-y-2 shadow-sm">
          {categoryItems.map(p => (
            <ProductCard 
              key={p.id} 
              product={p} 
              onAddToCart={addToCart} 
              onViewDetails={(p) => { setSelectedProduct(p); setCurrentView('product'); }} 
            />
          ))}
        </div>
      </div>
    );
  };

  if (isLoadingDB) {
    return (
      <div className="h-screen w-screen flex flex-col items-center justify-center bg-white dark:bg-slate-950">
        <div className="relative w-24 h-24 mb-6">
          <div className="absolute inset-0 border-4 border-skyblue-100 dark:border-slate-800 rounded-full"></div>
          <div className="absolute inset-0 border-4 border-skyblue-50 rounded-full border-t-transparent animate-spin"></div>
        </div>
        <h1 className="text-xl font-black text-slate-800 dark:text-white uppercase tracking-widest">NETTOOLZ Portal</h1>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex flex-col bg-slate-50 dark:bg-slate-950 transition-colors">
      <Navbar 
        cartCount={cart.reduce((acc, item) => acc + item.quantity, 0)} 
        isDarkMode={isDarkMode} 
        logoUrl={settings.logoUrl}
        currentUserEmail={currentUser?.email}
        onNavigate={setCurrentView} 
        onOpenCart={() => setIsCartOpen(true)} 
        onToggleTheme={() => { setIsDarkMode(!isDarkMode); document.documentElement.classList.toggle('dark'); }} 
      />

      <main className="flex-1 max-w-5xl mx-auto px-4 sm:px-6 lg:px-8 w-full py-8">
        {currentView === 'home' && (
          <div className="space-y-12">
            <section className="relative px-6 py-20 bg-gradient-to-br from-white to-slate-50 dark:from-slate-900 dark:to-slate-950 rounded-[3rem] border border-slate-100 dark:border-slate-800 overflow-hidden shadow-2xl">
              <div className="relative z-10 text-center max-w-3xl mx-auto">
                <span className="inline-block px-4 py-1.5 bg-skyblue-50 dark:bg-skyblue-900/30 text-skyblue-600 dark:text-skyblue-400 rounded-full text-[9px] font-black uppercase mb-6 tracking-[0.3em] border border-skyblue-100/50">Enterprise Vault</span>
                <h1 className="text-5xl sm:text-6xl font-black text-slate-900 dark:text-white leading-[1.1] mb-8 tracking-tighter uppercase">
                  Secure <span className="text-skyblue-500">Networking</span> Tools
                </h1>
                <p className="text-base text-slate-500 dark:text-slate-400 mb-10 leading-relaxed font-medium">
                  Verified high-performance assets for security professionals.
                </p>
                <div className="flex flex-col sm:flex-row items-center justify-center gap-4">
                  <button onClick={() => setCurrentView('category')} className="w-full sm:w-auto bg-skyblue-500 hover:bg-skyblue-600 text-white font-black px-10 py-4 rounded-2xl shadow-xl shadow-skyblue-500/20 transition-all active:scale-95 text-sm uppercase tracking-widest">
                    Explore Marketplace
                  </button>
                </div>
              </div>
            </section>

            {settings.categories.map(category => {
              const categoryProducts = products.filter(p => p.isVisible && p.category === category.id);
              return renderProductList(categoryProducts, category.name);
            })}
          </div>
        )}

        {currentView === 'category' && (
          <div className="py-8">
             <div className="flex flex-col md:flex-row items-start md:items-center justify-between mb-10 gap-6">
                <div>
                   <h2 className="text-3xl font-black dark:text-white tracking-tighter uppercase">Market <span className="text-skyblue-500">Archive</span></h2>
                   <p className="text-slate-400 text-sm font-bold mt-1">Filtering by: {selectedCategory ? settings.categories.find(c => c.id === selectedCategory)?.name : 'All Segments'}</p>
                </div>
                <div className="flex flex-wrap gap-2">
                   <button onClick={() => setSelectedCategory(null)} className={`px-5 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${!selectedCategory ? 'bg-skyblue-500 text-white' : 'bg-white dark:bg-slate-900 text-slate-400 border border-slate-100'}`}>All</button>
                   {settings.categories.map(c => (
                     <button key={c.id} onClick={() => setSelectedCategory(c.id)} className={`px-5 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${selectedCategory === c.id ? 'bg-skyblue-500 text-white' : 'bg-white dark:bg-slate-900 text-slate-400 border border-slate-100'}`}>{c.name}</button>
                   ))}
                </div>
             </div>

             <div className="space-y-4">
                {products.filter(p => p.isVisible && (!selectedCategory || p.category === selectedCategory)).map(p => (
                  <ProductCard key={p.id} product={p} onAddToCart={addToCart} onViewDetails={(p) => { setSelectedProduct(p); setCurrentView('product'); }} />
                ))}
             </div>
          </div>
        )}

        {currentView === 'product' && selectedProduct && (
          <div className="py-8">
            <button onClick={() => setCurrentView('category')} className="mb-8 text-slate-400 font-bold hover:text-skyblue-500 flex items-center transition-colors">
              <i className="fa-solid fa-arrow-left-long mr-2"></i> Back
            </button>
            <div className="bg-white dark:bg-slate-900 rounded-[2.5rem] p-8 border border-slate-100 dark:border-slate-800 flex flex-col md:flex-row gap-12 shadow-xl">
              <div className="flex-1 bg-slate-50 dark:bg-slate-950 rounded-3xl flex items-center justify-center p-8 aspect-square">
                <img src={selectedProduct.image} className="max-w-full max-h-full object-contain" alt={selectedProduct.name} />
              </div>
              <div className="flex-1 flex flex-col justify-center space-y-6">
                <span className="text-skyblue-500 font-black uppercase text-[10px] tracking-widest">{selectedProduct.category}</span>
                <h1 className="text-4xl font-black dark:text-white tracking-tighter uppercase">{selectedProduct.name}</h1>
                <div className="flex items-center space-x-4">
                  <p className="text-4xl font-black text-skyblue-600 dark:text-skyblue-400">₦{selectedProduct.price.toLocaleString()}</p>
                </div>
                <p className="text-sm text-slate-500 dark:text-slate-400 leading-relaxed font-medium">
                  {selectedProduct.description}
                </p>
                <div className="grid grid-cols-2 gap-3">
                  {selectedProduct.features.map((f, i) => (
                    <div key={i} className="flex items-center space-x-2 text-slate-600 dark:text-slate-400">
                      <i className="fa-solid fa-circle-check text-skyblue-400 text-[10px]"></i>
                      <span className="text-xs font-bold">{f}</span>
                    </div>
                  ))}
                </div>
                <button onClick={() => addToCart(selectedProduct)} className="w-full bg-skyblue-500 hover:bg-skyblue-600 text-white font-black py-4 rounded-2xl shadow-xl transition-all active:scale-95 mt-6 text-sm uppercase tracking-widest">
                  Secure Purchase
                </button>
              </div>
            </div>
          </div>
        )}

        {currentView === 'profile' && (
          currentUser ? (
            <UserProfile user={currentUser} settings={settings} onFundWallet={() => setCurrentView('fund_wallet')} onLogout={() => { setCurrentUser(null); localStorage.removeItem('nettoolz_logged_user_email'); setCurrentView('home'); }} />
          ) : (
            <UserAuth users={users} onAuth={handleAuth} onCancel={() => setCurrentView('home')} />
          )
        )}

        {currentView === 'fund_wallet' && <WalletFunding settings={settings} onBack={() => setCurrentView('profile')} onFundSuccess={handleFundSuccess} />}
        {currentView === 'admin_dashboard' && isAdminLoggedIn && <AdminDashboard products={products} settings={settings} admins={admins} onUpdateProducts={handleUpdateProducts} onUpdateSettings={handleUpdateSettings} onUpdateAdmins={handleUpdateAdmins} onLogout={() => { setIsAdminLoggedIn(false); localStorage.removeItem('nettoolz_admin_logged'); setCurrentView('home'); }} />}
        {currentView === 'admin_login' && <AdminLogin onLogin={(s) => { if(s) { setIsAdminLoggedIn(true); localStorage.setItem('nettoolz_admin_logged', 'true'); setCurrentView('admin_dashboard'); } }} onCancel={() => setCurrentView('home')} />}
      </main>

      {isCartOpen && (
        <div className="fixed inset-0 z-[110] flex justify-end">
          <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm" onClick={() => setIsCartOpen(false)}></div>
          <div className="relative w-full max-sm bg-white dark:bg-slate-900 h-full p-8 flex flex-col shadow-2xl animate-in slide-in-from-right duration-300">
            <div className="flex items-center justify-between mb-8">
              <h2 className="text-3xl font-black dark:text-white tracking-tighter uppercase">Cart</h2>
              <button onClick={() => setIsCartOpen(false)} className="text-slate-400 hover:text-slate-900"><i className="fa-solid fa-xmark text-xl"></i></button>
            </div>

            <div className="flex-1 overflow-y-auto space-y-4 custom-scrollbar pr-2">
              {cart.map(item => (
                <div key={item.id} className="flex gap-4 p-4 bg-slate-50 dark:bg-slate-800 rounded-2xl border border-slate-100 dark:border-slate-700">
                  <div className="w-16 h-16 bg-white dark:bg-slate-900 rounded-xl flex items-center justify-center p-2">
                    <img src={item.image} className="w-full h-full object-contain" alt={item.name} />
                  </div>
                  <div className="flex-1">
                    <p className="font-black dark:text-white text-sm leading-tight mb-1 uppercase">{item.name}</p>
                    <div className="flex items-center justify-between">
                      <p className="text-skyblue-600 dark:text-skyblue-400 font-black text-xs">₦{item.price.toLocaleString()}</p>
                      <span className="text-[10px] font-black text-slate-400 uppercase">Qty: {item.quantity}</span>
                    </div>
                  </div>
                  <button onClick={() => setCart(cart.filter(i => i.id !== item.id))} className="text-slate-300 hover:text-red-500 transition-colors"><i className="fa-solid fa-trash-can text-sm"></i></button>
                </div>
              ))}
              {cart.length === 0 && (
                <div className="text-center py-20 opacity-30">
                  <i className="fa-solid fa-shopping-basket text-5xl mb-4"></i>
                  <p className="text-xs font-black uppercase tracking-widest">Your cart is empty</p>
                </div>
              )}
            </div>

            {cart.length > 0 && (
              <div className="pt-6 border-t dark:border-slate-800 mt-auto">
                <div className="flex justify-between text-2xl font-black mb-8 dark:text-white tracking-tighter uppercase">
                  <span>Total</span>
                  <span className="text-skyblue-500">₦{cart.reduce((a, i) => a + (i.price * i.quantity), 0).toLocaleString()}</span>
                </div>
                <button onClick={handleCheckout} disabled={isProcessingCheckout} className="w-full bg-skyblue-500 text-white font-black py-4 rounded-xl shadow-lg hover:bg-skyblue-600 transition-all active:scale-95 disabled:bg-slate-300 text-xs uppercase tracking-widest">
                  {isProcessingCheckout ? "Processing..." : "Confirm Checkout"}
                </button>
              </div>
            )}
          </div>
        </div>
      )}

      <footer className="bg-white dark:bg-slate-950 border-t border-slate-100 dark:border-slate-900 py-12 text-center mt-auto">
        <div className="max-w-7xl mx-auto px-4">
          <div className="flex flex-col items-center mb-6">
             <div className="mb-4">
                <LogoIcon />
             </div>
            <div className="text-2xl font-black tracking-tighter text-slate-900 dark:text-white">
              NET<span className="text-skyblue-500">TOOLZ</span>
            </div>
          </div>
          <p className="text-slate-400 text-[9px] font-black uppercase tracking-[0.3em]">© 2024 NETTOOLZ Enterprise • Premium Network Assets</p>
          <button onClick={() => setCurrentView('admin_login')} className="mt-4 text-[9px] text-slate-300 hover:text-skyblue-500 font-black tracking-widest transition-colors opacity-30">SYSTEM ACCESS</button>
        </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useRef } from 'react';
import { Product, Category, SiteSettings, AdminUser, PaymentMethod } from '../types';

interface AdminDashboardProps {
  products: Product[];
  settings: SiteSettings;
  admins: AdminUser[];
  onUpdateProducts: (newProducts: Product[]) => void;
  onUpdateSettings: (newSettings: SiteSettings) => void;
  onUpdateAdmins: (newAdmins: AdminUser[]) => void;
  onLogout: () => void;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ 
  products, settings, admins, onUpdateProducts, onUpdateSettings, onUpdateAdmins, onLogout 
}) => {
  const [activeTab, setActiveTab] = useState<'products' | 'categories' | 'settings' | 'admins' | 'payments'>('products');
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);
  const [editingCategory, setEditingCategory] = useState<Category | null>(null);
  const [editingPayment, setEditingPayment] = useState<PaymentMethod | null>(null);
  const [productToDelete, setProductToDelete] = useState<Product | null>(null);
  const [categoryToDelete, setCategoryToDelete] = useState<Category | null>(null);
  const [adminToDelete, setAdminToDelete] = useState<AdminUser | null>(null);
  const [showCreateForm, setShowCreateForm] = useState(false);
  const [showCategoryForm, setShowCategoryForm] = useState(false);
  const [showAdminForm, setShowAdminForm] = useState(false);

  // Bulk & Global Actions State
  const [selectedProductIds, setSelectedProductIds] = useState<string[]>([]);
  const [showBulkDeleteConfirm, setShowBulkDeleteConfirm] = useState(false);
  const [showBulkCategoryModal, setShowBulkCategoryModal] = useState(false);
  const [bulkCategoryTarget, setBulkCategoryTarget] = useState<string>(settings.categories[0]?.id || '');

  const editFileInputRef = useRef<HTMLInputElement>(null);

  // Form states
  const [newProduct, setNewProduct] = useState({
    name: '', description: '', price: '', category: settings.categories[0]?.id || '',
    stock: '', image: '', features: '', secretContent: ''
  });

  const [newCategory, setNewCategory] = useState({ name: '', icon: 'fa-box' });
  const [newAdmin, setNewAdmin] = useState({ username: '', role: 'editor' as 'super' | 'editor' });

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>, isEdit = false) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64 = reader.result as string;
        if (isEdit && editingProduct) setEditingProduct({ ...editingProduct, image: base64 });
        else setNewProduct({ ...newProduct, image: base64 });
      };
      reader.readAsDataURL(file);
    }
  };

  const handleCreateProduct = (e: React.FormEvent) => {
    e.preventDefault();
    const product: Product = {
      id: Date.now().toString(),
      name: newProduct.name,
      description: newProduct.description,
      price: parseFloat(newProduct.price),
      category: newProduct.category,
      stock: parseInt(newProduct.stock),
      rating: 5.0,
      image: newProduct.image || 'https://picsum.photos/seed/tool/400/300',
      features: newProduct.features.split(',').map(f => f.trim()).filter(f => f !== ''),
      isVisible: true,
      secretContent: newProduct.secretContent
    };
    onUpdateProducts([product, ...products]);
    setShowCreateForm(false);
    setNewProduct({ name: '', description: '', price: '', category: settings.categories[0]?.id || '', stock: '', image: '', features: '', secretContent: '' });
  };

  const handleSaveProductEdit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingProduct) return;
    onUpdateProducts(products.map(p => p.id === editingProduct.id ? editingProduct : p));
    setEditingProduct(null);
  };

  // Bulk Operations
  const toggleSelectAll = () => {
    if (selectedProductIds.length === products.length && products.length > 0) {
      setSelectedProductIds([]);
    } else {
      setSelectedProductIds(products.map(p => p.id));
    }
  };

  const toggleSelectProduct = (id: string) => {
    setSelectedProductIds(prev => 
      prev.includes(id) ? prev.filter(pId => pId !== id) : [...prev, id]
    );
  };

  const bulkUpdateVisibility = (visible: boolean) => {
    onUpdateProducts(products.map(p => 
      selectedProductIds.includes(p.id) ? { ...p, isVisible: visible } : p
    ));
    setSelectedProductIds([]);
  };

  const bulkDeleteProducts = () => {
    onUpdateProducts(products.filter(p => !selectedProductIds.includes(p.id)));
    setSelectedProductIds([]);
    setShowBulkDeleteConfirm(false);
  };

  const bulkUpdateCategory = () => {
    onUpdateProducts(products.map(p => 
      selectedProductIds.includes(p.id) ? { ...p, category: bulkCategoryTarget } : p
    ));
    setSelectedProductIds([]);
    setShowBulkCategoryModal(false);
  };

  const bulkUpdateStock = (amount: number) => {
    onUpdateProducts(products.map(p => 
      selectedProductIds.includes(p.id) ? { ...p, stock: Math.max(0, p.stock + amount) } : p
    ));
  };

  const handleCreateCategory = (e: React.FormEvent) => {
    e.preventDefault();
    const cat: Category = {
      id: newCategory.name.toLowerCase().replace(/\s+/g, '-'),
      name: newCategory.name,
      icon: newCategory.icon
    };
    onUpdateSettings({ ...settings, categories: [...settings.categories, cat] });
    setShowCategoryForm(false);
    setNewCategory({ name: '', icon: 'fa-box' });
  };

  const handleSaveCategoryEdit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingCategory) return;
    onUpdateSettings({
      ...settings,
      categories: settings.categories.map(c => c.id === editingCategory.id ? editingCategory : c)
    });
    setEditingCategory(null);
  };

  const handleCreateAdmin = (e: React.FormEvent) => {
    e.preventDefault();
    const admin: AdminUser = {
      id: Date.now().toString(),
      username: newAdmin.username,
      role: newAdmin.role
    };
    onUpdateAdmins([...admins, admin]);
    setShowAdminForm(false);
    setNewAdmin({ username: '', role: 'editor' });
  };

  const handleSavePayment = (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingPayment) return;
    const methods = settings.paymentMethods.map(m => m.id === editingPayment.id ? editingPayment : m);
    onUpdateSettings({ ...settings, paymentMethods: methods });
    setEditingPayment(null);
  };

  return (
    <div className="flex flex-col md:flex-row min-h-[85vh] bg-white dark:bg-slate-900 rounded-[2.5rem] border border-skyblue-100 dark:border-slate-800 overflow-hidden shadow-[0_20px_50px_rgba(14,165,233,0.05)] mb-12 transition-all">
      {/* Sidebar Navigation */}
      <div className="w-full md:w-72 bg-slate-900 p-10 shrink-0 flex flex-col">
        <div className="flex items-center space-x-3 mb-16">
          <div className="bg-skyblue-500 p-2 rounded-xl text-white shadow-lg shadow-skyblue-500/20">
            <i className="fa-solid fa-gauge-high"></i>
          </div>
          <h2 className="text-xl font-black text-white tracking-tighter uppercase">NetToolz Control</h2>
        </div>

        <nav className="space-y-3 flex-1">
          <button onClick={() => setActiveTab('products')} className={`w-full text-left px-5 py-4 rounded-2xl font-bold flex items-center space-x-4 transition-all ${activeTab === 'products' ? 'bg-skyblue-500 text-white shadow-xl shadow-skyblue-500/20' : 'text-slate-400 hover:text-white hover:bg-white/5'}`}>
            <i className="fa-solid fa-cube w-5"></i><span>Inventory</span>
          </button>
          <button onClick={() => setActiveTab('categories')} className={`w-full text-left px-5 py-4 rounded-2xl font-bold flex items-center space-x-4 transition-all ${activeTab === 'categories' ? 'bg-skyblue-500 text-white shadow-xl shadow-skyblue-500/20' : 'text-slate-400 hover:text-white hover:bg-white/5'}`}>
            <i className="fa-solid fa-tags w-5"></i><span>Categories</span>
          </button>
          <button onClick={() => setActiveTab('admins')} className={`w-full text-left px-5 py-4 rounded-2xl font-bold flex items-center space-x-4 transition-all ${activeTab === 'admins' ? 'bg-skyblue-500 text-white shadow-xl shadow-skyblue-500/20' : 'text-slate-400 hover:text-white hover:bg-white/5'}`}>
            <i className="fa-solid fa-user-shield w-5"></i><span>Staff Portal</span>
          </button>
          <button onClick={() => setActiveTab('payments')} className={`w-full text-left px-5 py-4 rounded-2xl font-bold flex items-center space-x-4 transition-all ${activeTab === 'payments' ? 'bg-skyblue-500 text-white shadow-xl shadow-skyblue-500/20' : 'text-slate-400 hover:text-white hover:bg-white/5'}`}>
            <i className="fa-solid fa-code w-5"></i><span>API Integrations</span>
          </button>
          <button onClick={() => setActiveTab('settings')} className={`w-full text-left px-5 py-4 rounded-2xl font-bold flex items-center space-x-4 transition-all ${activeTab === 'settings' ? 'bg-skyblue-500 text-white shadow-xl shadow-skyblue-500/20' : 'text-slate-400 hover:text-white hover:bg-white/5'}`}>
            <i className="fa-solid fa-sliders w-5"></i><span>Site Config</span>
          </button>
        </nav>

        <button onClick={onLogout} className="mt-12 w-full text-left px-5 py-4 text-red-400 font-bold hover:bg-red-500/10 rounded-2xl transition-all">
          <i className="fa-solid fa-power-off mr-3"></i><span>Secure Logout</span>
        </button>
      </div>

      {/* Main Content Area */}
      <div className="flex-1 p-10 bg-skyblue-50/10 dark:bg-slate-900/40 overflow-y-auto custom-scrollbar">
        <header className="flex flex-col sm:flex-row justify-between items-start sm:items-center mb-12 gap-6">
          <div>
            <h3 className="text-4xl font-black dark:text-white tracking-tighter capitalize">{activeTab}</h3>
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.3em] mt-2">Enterprise Management Unit</p>
          </div>

          <div className="flex items-center space-x-3">
            {activeTab === 'products' && (
              <button 
                onClick={() => setShowCreateForm(!showCreateForm)}
                className={`flex items-center space-x-3 font-black px-8 py-4 rounded-2xl shadow-xl transition-all active:scale-95 ${showCreateForm ? 'bg-slate-800 text-white' : 'bg-skyblue-500 text-white shadow-skyblue-500/20'}`}
              >
                <i className={`fa-solid ${showCreateForm ? 'fa-xmark' : 'fa-plus'}`}></i>
                <span>{showCreateForm ? 'Discard' : 'Deploy New Asset'}</span>
              </button>
            )}
            {activeTab === 'categories' && (
              <button onClick={() => setShowCategoryForm(true)} className="bg-skyblue-500 text-white font-black px-8 py-4 rounded-2xl shadow-xl shadow-skyblue-500/20 transition-all active:scale-95">
                <i className="fa-solid fa-folder-plus mr-2"></i>New Segment
              </button>
            )}
            {activeTab === 'admins' && (
              <button onClick={() => setShowAdminForm(true)} className="bg-skyblue-500 text-white font-black px-8 py-4 rounded-2xl shadow-xl shadow-skyblue-500/20 transition-all active:scale-95">
                <i className="fa-solid fa-user-plus mr-2"></i>Provision Account
              </button>
            )}
          </div>
        </header>

        {/* Tab: Products */}
        {activeTab === 'products' && (
          <div className="space-y-8 animate-in fade-in duration-500">
            {showCreateForm && (
               <form onSubmit={handleCreateProduct} className="bg-white dark:bg-slate-800 p-10 rounded-[2.5rem] border border-skyblue-100 dark:border-slate-700 shadow-2xl space-y-6 animate-in slide-in-from-top-4">
                 <h4 className="text-2xl font-black dark:text-white mb-6">Asset Specifications</h4>
                 <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    <div className="space-y-2">
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block px-1">Product Identity</label>
                      <input required type="text" value={newProduct.name} onChange={e => setNewProduct({...newProduct, name: e.target.value})} className="w-full bg-skyblue-50/50 dark:bg-slate-900 p-4 rounded-2xl border border-skyblue-100 dark:border-slate-700 dark:text-white font-bold" placeholder="e.g. Proxy Suite v4" />
                    </div>
                    <div className="space-y-2">
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block px-1">Price Point (NGN)</label>
                      <input required type="number" value={newProduct.price} onChange={e => setNewProduct({...newProduct, price: e.target.value})} className="w-full bg-skyblue-50/50 dark:bg-slate-900 p-4 rounded-2xl border border-skyblue-100 dark:border-slate-700 dark:text-white font-bold" />
                    </div>
                    <div className="space-y-2">
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block px-1">Initial Inventory</label>
                      <input required type="number" value={newProduct.stock} onChange={e => setNewProduct({...newProduct, stock: e.target.value})} className="w-full bg-skyblue-50/50 dark:bg-slate-900 p-4 rounded-2xl border border-skyblue-100 dark:border-slate-700 dark:text-white font-bold" />
                    </div>
                    <div className="space-y-2">
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block px-1">Classification</label>
                      <select value={newProduct.category} onChange={e => setNewProduct({...newProduct, category: e.target.value})} className="w-full bg-skyblue-50/50 dark:bg-slate-900 p-4 rounded-2xl border border-skyblue-100 dark:border-slate-700 dark:text-white font-bold">
                        {settings.categories.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                      </select>
                    </div>
                    <div className="md:col-span-2 space-y-2">
                       <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block px-1">Secure Credential Payload</label>
                       <textarea value={newProduct.secretContent} onChange={e => setNewProduct({...newProduct, secretContent: e.target.value})} className="w-full bg-skyblue-50/50 dark:bg-slate-900 p-5 rounded-2xl border border-skyblue-100 dark:border-slate-700 dark:text-white font-mono text-sm h-32" placeholder="Delivered to user after purchase..." />
                    </div>
                 </div>
                 <div className="flex justify-end pt-6">
                   <button type="submit" className="bg-skyblue-500 text-white font-black px-12 py-4 rounded-2xl shadow-xl shadow-skyblue-500/20 active:scale-95 transition-all">Finalize & Deploy</button>
                 </div>
               </form>
            )}

            {/* Bulk Actions Floating Bar */}
            {selectedProductIds.length > 0 && (
              <div className="bg-slate-900 text-white px-8 py-5 rounded-[2rem] shadow-[0_20px_60px_rgba(0,0,0,0.3)] flex flex-wrap items-center justify-between gap-6 animate-in slide-in-from-top-6 duration-300 sticky top-4 z-40 border border-white/5 backdrop-blur-md bg-slate-900/95">
                <div className="flex items-center space-x-6">
                  <div className="flex items-center justify-center w-12 h-12 bg-skyblue-500 text-white rounded-2xl shadow-lg">
                    <span className="font-black">{selectedProductIds.length}</span>
                  </div>
                  <div>
                    <h5 className="font-black text-lg leading-tight">Batch Selection</h5>
                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-0.5">Assets are primed for action</p>
                  </div>
                </div>

                <div className="flex flex-wrap items-center gap-3">
                  <div className="flex bg-white/5 p-1.5 rounded-2xl border border-white/10">
                    <button onClick={() => bulkUpdateVisibility(true)} className="px-5 py-2.5 rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-white/10 transition-all text-skyblue-400"><i className="fa-solid fa-eye mr-2"></i>Show</button>
                    <button onClick={() => bulkUpdateVisibility(false)} className="px-5 py-2.5 rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-white/10 transition-all text-slate-400"><i className="fa-solid fa-eye-slash mr-2"></i>Hide</button>
                  </div>

                  <div className="flex bg-white/5 p-1.5 rounded-2xl border border-white/10">
                    <button onClick={() => setShowBulkCategoryModal(true)} className="px-5 py-2.5 rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-white/10 transition-all text-white"><i className="fa-solid fa-folder-tree mr-2"></i>Move</button>
                    <button onClick={() => bulkUpdateStock(10)} className="px-5 py-2.5 rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-white/10 transition-all text-white"><i className="fa-solid fa-plus mr-1"></i>10 Stock</button>
                  </div>

                  <button onClick={() => setShowBulkDeleteConfirm(true)} className="bg-red-500 hover:bg-red-600 text-white font-black px-6 py-3.5 rounded-2xl shadow-xl shadow-red-500/20 text-[10px] uppercase tracking-[0.2em] transition-all active:scale-95">
                    <i className="fa-solid fa-trash-can mr-2"></i>Terminal Delete
                  </button>

                  <button onClick={() => setSelectedProductIds([])} className="w-12 h-12 flex items-center justify-center text-slate-400 hover:text-white transition-colors">
                    <i className="fa-solid fa-xmark text-xl"></i>
                  </button>
                </div>
              </div>
            )}

            <div className="bg-white dark:bg-slate-800 rounded-[2.5rem] border border-skyblue-100 dark:border-slate-700 overflow-hidden shadow-sm transition-all">
              <div className="overflow-x-auto">
                <table className="w-full text-left">
                  <thead className="bg-skyblue-50/50 dark:bg-slate-900/50 text-slate-400 text-[10px] font-black uppercase tracking-[0.2em]">
                    <tr>
                      <th className="px-8 py-6 w-12 text-center">
                        <input type="checkbox" checked={selectedProductIds.length === products.length && products.length > 0} onChange={toggleSelectAll} className="w-5 h-5 rounded-lg text-skyblue-500 border-skyblue-200 focus:ring-skyblue-500 cursor-pointer" />
                      </th>
                      <th className="px-8 py-6">Digital Asset</th>
                      <th className="px-8 py-6">Financials</th>
                      <th className="px-8 py-6">Availability</th>
                      <th className="px-8 py-6 text-center">Control</th>
                    </tr>
                  </thead>
                  <tbody className="text-sm dark:text-slate-300">
                    {products.length === 0 ? (
                      <tr><td colSpan={5} className="px-8 py-24 text-center text-slate-400 italic font-medium">No assets currently registered in the inventory.</td></tr>
                    ) : (
                      products.map(p => {
                        const isSelected = selectedProductIds.includes(p.id);
                        return (
                          <tr key={p.id} className={`border-t border-skyblue-50 dark:border-slate-700 transition-all ${isSelected ? 'bg-skyblue-50 dark:bg-skyblue-900/10' : 'hover:bg-skyblue-50/20 dark:hover:bg-slate-900/10'}`}>
                            <td className="px-8 py-6 text-center">
                              <input type="checkbox" checked={isSelected} onChange={() => toggleSelectProduct(p.id)} className="w-5 h-5 rounded-lg text-skyblue-500 border-skyblue-200 cursor-pointer" />
