              <div className="md:col-span-2 space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block px-1">Credential Payload</label>
                <textarea value={editingProduct.secretContent} onChange={e => setEditingProduct({...editingProduct, secretContent: e.target.value})} className="w-full bg-skyblue-50/50 dark:bg-slate-800 p-5 rounded-2xl border border-skyblue-100 dark:border-slate-700 dark:text-white font-mono text-sm h-32" />
