                  </div>
                  <button onClick={() => setCart(cart.filter(i => i.id !== item.id))} className="text-slate-300 hover:text-red-500 transition-colors"><i className="fa-solid fa-trash-can text-sm"></i></button>
                </div>
              ))}
              {cart.length === 0 && (
                <div className="text-center py-20 opacity-30">
                  <i className="fa-solid fa-shopping-basket text-5xl mb-4"></i>
