                <LogoIcon />
             </div>
            <div className="text-2xl font-black tracking-tighter text-slate-900 dark:text-white">
              NET<span className="text-skyblue-500">TOOLZ</span>
            </div>
          </div>
          <p className="text-slate-400 text-[9px] font-black uppercase tracking-[0.3em]">© 2024 NETTOOLZ Enterprise • Premium Network Assets</p>
          <button onClick={() => setCurrentView('admin_login')} className="mt-4 text-[9px] text-slate-300 hover:text-skyblue-500 font-black tracking-widest transition-colors opacity-30">SYSTEM ACCESS</button>
