                </div>
                <button onClick={() => addToCart(selectedProduct)} className="w-full bg-skyblue-500 hover:bg-skyblue-600 text-white font-black py-4 rounded-2xl shadow-xl transition-all active:scale-95 mt-6 text-sm uppercase tracking-widest">
