                  <span className="text-skyblue-500">₦{cart.reduce((a, i) => a + (i.price * i.quantity), 0).toLocaleString()}</span>
                </div>
                <button onClick={handleCheckout} disabled={isProcessingCheckout} className="w-full bg-skyblue-500 text-white font-black py-4 rounded-xl shadow-lg hover:bg-skyblue-600 transition-all active:scale-95 disabled:bg-slate-300 text-xs uppercase tracking-widest">
                  {isProcessingCheckout ? "Processing..." : "Confirm Checkout"}
                </button>
              </div>
            )}
          </div>
        </div>
      )}

      <footer className="bg-white dark:bg-slate-950 border-t border-slate-100 dark:border-slate-900 py-12 text-center mt-auto">
        <div className="max-w-7xl mx-auto px-4">
          <div className="flex flex-col items-center mb-6">
             <div className="mb-4">
                <LogoIcon />
             </div>
            <div className="text-2xl font-black tracking-tighter text-slate-900 dark:text-white">
              NET<span className="text-skyblue-500">TOOLZ</span>
            </div>
          </div>
          <p className="text-slate-400 text-[9px] font-black uppercase tracking-[0.3em]">© 2024 NETTOOLZ Enterprise • Premium Network Assets</p>
          <button onClick={() => setCurrentView('admin_login')} className="mt-4 text-[9px] text-slate-300 hover:text-skyblue-500 font-black tracking-widest transition-colors opacity-30">SYSTEM ACCESS</button>
        </div>
      </footer>
    </div>
  );
};

export default App;

